pub mod task;
pub mod timer;
pub mod trap;

use core::arch::global_asm;
#[cfg(target_arch = "riscv64")]
global_asm!(include_str!("entry-rv.asm"));
#[cfg(target_arch = "loongarch64")]
global_asm!(include_str!("entry-la.asm"));
fn clear_bss() {
    extern "C" {
        fn sbss();
        fn ebss();
    }
    unsafe {
        core::slice::from_raw_parts_mut(sbss as usize as *mut u8, ebss as usize - sbss as usize)
            .fill(0);
    }
}

#[no_mangle]
/// the rust entry-point of os
pub fn rust_main() -> ! {
    clear_bss();
    logging::init();
    #[cfg(target_arch = "loongarch64")]
    {
        arch::print_arch_info();
    }
    mm::init();
    #[cfg(target_arch = "riscv64")]
    mm::remap_test();
    trap::init();
    trap::enable_timer_interrupt();
    timer::set_next_trigger();
    // drivers::block::block_device_test();
    // drivers::block::file_test();
    // drivers::block::io_test();
    task::add_initproc();
    task::run_tasks();
    panic!("Unreachable in rust_main!");
}

//! Constants in the kernel

#[allow(unused)]

/// user app's stack size
pub const USER_STACK_SIZE: usize = PAGE_SIZE * 1024;
/// user app's heap size
pub const USER_HEAP_SIZE: usize = PAGE_SIZE * 1024 * 512;
/// kernel stack size
pub const KERNEL_STACK_SIZE: usize = PAGE_SIZE * 32;
/// kernel heap size (increased for heap-based kernel stacks on LoongArch)
pub const KERNEL_HEAP_SIZE: usize = 0x800_0000; // 128MB

/// physical memory end address (RISC-V QEMU virt)
#[cfg(target_arch = "riscv64")]
pub const MEMORY_END: usize = 0xC000_0000;

/// Start of the low RAM region (inclusive).
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_LOW_START: usize = 0x0000_0000;
/// End of the low RAM region (exclusive), 256 MiB.
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_LOW_END: usize = 0x1000_0000;
/// Start of the unmapped hole between low and high RAM (inclusive).
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_HOLE_START: usize = 0x1000_0000;
/// End of the unmapped hole (exclusive).
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_HOLE_END: usize = 0x9000_0000;
/// Start of the high RAM region (inclusive).
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_HIGH_START: usize = 0x9000_0000;
/// End of the high RAM region (exclusive), 768 MiB with `-m 1G`.
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_HIGH_END: usize = 0xC000_0000;

/// Alias kept for code not yet ported to split regions.
#[cfg(target_arch = "loongarch64")]
pub const MEMORY_END: usize = MEMORY_HIGH_END;



/// page size : 4KB
pub const PAGE_SIZE: usize = 0x1000;
/// page size bits: 12
pub const PAGE_SIZE_BITS: usize = 0xc;
/// the virtual addr of trapoline
pub const TRAMPOLINE: usize = usize::MAX - PAGE_SIZE + 1;
/// the virtual addr of trap context
pub const TRAP_CONTEXT_BASE: usize = TRAMPOLINE - PAGE_SIZE;
/// Logging buffer size
pub const LOG_BUFFER_SIZE: usize = PAGE_SIZE * 4;

/// LoongArch QEMU virt 16550 UART physical base (`hw/loongarch/virt.c`).
#[cfg(target_arch = "loongarch64")]
pub const UART_PHYS_BASE: usize = 0x1fe0_01e0;

/// Uncached DMW virt prefix (must match `entry-la.asm` DMWIN0).
#[cfg(target_arch = "loongarch64")]
pub const DMW0_UNCACHE_BASE: usize = 0x8000_0000_0000_0000;

/// Cached DMW virt prefix (must match `entry-la.asm` DMWIN1).
#[cfg(target_arch = "loongarch64")]
pub const DMW1_CACHE_BASE: usize = 0x9000_0000_0000_0000;

/// UART MMIO address for early console: DMW0 uncache window + physical UART.
#[cfg(target_arch = "loongarch64")]
pub const UART_BASE: usize = DMW0_UNCACHE_BASE | UART_PHYS_BASE;

/// QEMU ACPI poweroff register (physical, `hw/loongarch` TCG tests).
#[cfg(target_arch = "loongarch64")]
pub const POWEROFF_PHYS_BASE: usize = 0x100e_001c;

/// Poweroff MMIO via DMW0 uncache window.
#[cfg(target_arch = "loongarch64")]
pub const POWEROFF_BASE: usize = DMW0_UNCACHE_BASE | POWEROFF_PHYS_BASE;

/// Value written to [`POWEROFF_BASE`] to shut down QEMU.
#[cfg(target_arch = "loongarch64")]
pub const POWEROFF_VALUE: u8 = 0x34;

/// Map a physical address into the cached DMW1 kernel window.
#[cfg(target_arch = "loongarch64")]
#[inline]
pub fn phys_to_cached_va(pa: usize) -> usize {
    DMW1_CACHE_BASE | pa
}

/// Convert a DMW window address to physical address.
#[cfg(target_arch = "loongarch64")]
#[inline]
pub fn dmw_to_phys(addr: usize) -> usize {
    if addr >= DMW1_CACHE_BASE {
        addr - DMW1_CACHE_BASE
    } else if addr >= DMW0_UNCACHE_BASE {
        addr - DMW0_UNCACHE_BASE
    } else {
        addr
    }
}

