use loongArch64::register::tcfg;
/// The number of ticks per second
const TICKS_PER_SEC: usize = 100;
/// The number of milliseconds per second
const MSEC_PER_SEC: usize = 1000;
/// The number of microseconds per second
#[allow(dead_code)]
const MICRO_PER_SEC: usize = 1_000_000;

#[cfg(target_arch = "riscv64")]
/// Get the current time in ticks (RISC-V `time` CSR).
pub fn get_time() -> usize {
    time::read()
}

#[cfg(target_arch = "loongarch64")]
/// Get the current time in ticks (LoongArch `rdtime.d`).
pub fn get_time() -> usize {
    let mut time: usize;
    unsafe {
        core::arch::asm!("rdtime.d {}, $zero", out(reg) time, options(nomem, nostack));
    }
    time
}

/// Get the current time in milliseconds
pub fn get_time_ms() -> usize {
    get_time() * MSEC_PER_SEC / CLOCK_FREQ
}

/// get current time in microseconds
pub fn get_time_us() -> usize {
    get_time() * MICRO_PER_SEC / CLOCK_FREQ
}

#[cfg(target_arch = "riscv64")]
/// Set the next timer interrupt (SBI `set_timer`).
pub fn set_next_trigger() {
    let time = get_time();
    let next = time + CLOCK_FREQ / TICKS_PER_SEC;
    set_timer(next);
}

#[cfg(target_arch = "loongarch64")]
/// Set the next timer interrupt (LoongArch TCFG one-shot).
pub fn set_next_trigger() {
    let interval = (CLOCK_FREQ / TICKS_PER_SEC) as u32;
    tcfg::set_init_val(interval as usize);
    tcfg::set_periodic(false);
    tcfg::set_en(true);
}

/// 定时器类型
#[derive(PartialEq, Eq, Clone, Copy, Debug)]
pub enum TimerKind {
    /// 普通睡眠
    Sleep,
    /// ITIMER_REAL，到期发送 SIGALRM
    ITimerReal,
    /// ITIMER_VIRTUAL，到期发送 SIGVTALRM
    ITimerVirtual,
    /// ITIMER_PROF，到期发送 SIGPROF
    ITimerProf,
}

/// condvar for timer
pub struct TimerCondVar {
    /// The time when the timer expires, in microseconds
    pub expire_us: usize,
    /// The task to be woken up when the timer expires
    pub task: Arc<TaskControlBlock>,
    /// 定时器类型
    pub kind: TimerKind,
}

impl PartialEq for TimerCondVar {
    fn eq(&self, other: &Self) -> bool {
        self.expire_us == other.expire_us
    }
}
impl Eq for TimerCondVar {}
impl PartialOrd for TimerCondVar {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        let a = -(self.expire_us as isize);
        let b = -(other.expire_us as isize);
        Some(a.cmp(&b))
    }
}

impl Ord for TimerCondVar {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap()
    }
}

lazy_static! {
    /// TIMERS: global instance: set of timer condvars
    static ref TIMERS: UPSafeCell<BinaryHeap<TimerCondVar>> =
        unsafe { UPSafeCell::new(BinaryHeap::<TimerCondVar>::new()) };
}

/// 添加定时器（微秒精度）
pub fn add_timer(expire_us: usize, task: Arc<TaskControlBlock>) {
    add_timer_kind(expire_us, task, TimerKind::Sleep);
}

/// 添加指定类型的定时器（微秒精度）
pub fn add_timer_kind(expire_us: usize, task: Arc<TaskControlBlock>, kind: TimerKind) {
    let now = get_time_us();
    info!(
        "kernel:pid[{}] add_timer kind={:?} expire_us={} now={} delay_us={}",
        current_task().unwrap().process.upgrade().unwrap().getpid(), kind, expire_us, now,
        if expire_us > now { expire_us - now } else { 0 }
    );
    let mut timers = TIMERS.exclusive_access();
    timers.push(TimerCondVar { expire_us, task, kind });
}

/// Remove a timer
pub fn remove_timer(task: Arc<TaskControlBlock>) {
    let mut timers = TIMERS.exclusive_access();
    let mut temp = BinaryHeap::<TimerCondVar>::new();
    for condvar in timers.drain() {
        if Arc::as_ptr(&task) != Arc::as_ptr(&condvar.task) {
            temp.push(condvar);
        }
    }
    timers.clear();
    timers.append(&mut temp);
}

/// Remove a timer
pub fn remove_timer_kind(task: Arc<TaskControlBlock>, kind: TimerKind) {
    let mut timers = TIMERS.exclusive_access();
    let mut temp = BinaryHeap::<TimerCondVar>::new();
    info!("kernel:pid[{}] remove_timer kind={:?}", 
    current_task().unwrap().process.upgrade().unwrap().getpid(), kind);
    for condvar in timers.drain() {
        if Arc::as_ptr(&task) == Arc::as_ptr(&condvar.task) && condvar.kind == kind {
            continue; 
        }
        temp.push(condvar);
    }
    timers.clear();
    timers.append(&mut temp);
}

/// 检查并处理到期的定时器
pub fn check_timer() {
    let current_us = get_time_us();
    let timers = TIMERS.exclusive_access();
    let _timer_count = timers.len();
    drop(timers);
    let mut timers = TIMERS.exclusive_access();
    let mut expired = Vec::new();
    // 先收集所有到期定时器
    while let Some(timer) = timers.peek() {
        if timer.expire_us <= current_us {
            let t = timers.pop().unwrap();
            expired.push(t);
        } else {
            break;
        }
    }
    drop(timers);
    // 处理到期定时器
    let mut to_rearm = Vec::new();
    // trace!("[check_timer] processing {} expired timers", expired.len());
    for (_i, timer) in expired.iter().enumerate() {
        match timer.kind {
            // 🌟 核心修改点 2：统一处理三种区间计时器
            TimerKind::ITimerReal | TimerKind::ITimerVirtual | TimerKind::ITimerProf => {
                if let Some(proc) = timer.task.process.upgrade() {
                    let mut inner = proc.inner_exclusive_access();
                    let (idx, signal) = match timer.kind {
                        TimerKind::ITimerReal => (0, SignalFlags::SIGALRM),
                        TimerKind::ITimerVirtual => (1, SignalFlags::SIGVTALRM),
                        TimerKind::ITimerProf => (2, SignalFlags::SIGPROF),
                        _ => unreachable!(),
                    };
                    inner.signals |= signal;
                    let (ival_sec, ival_usec, _, _, _) = inner.itimers[idx];
                    if ival_sec > 0 || ival_usec > 0 {
                        let now_us = get_time_us() as u64;
                        let next_us = now_us + (ival_sec as u64) * 1_000_000 + (ival_usec as u64);
                        inner.itimers[idx] = (ival_sec, ival_usec, ival_sec, ival_usec, now_us);
                        to_rearm.push((next_us as usize, Arc::clone(&timer.task), timer.kind));
                    }
                    drop(inner);
                }
            }
            _ => {}
        }
        wakeup_task(Arc::clone(&timer.task));
    }
    // 重新注册周期性定时器
    if !to_rearm.is_empty() {
        let mut timers = TIMERS.exclusive_access();
        for (next_us, task, kind) in to_rearm {
            timers.push(TimerCondVar { expire_us: next_us, task, kind });
        }
    }
}

//! Trap handling functionality
//!
//! For rCore, we have a single trap entry point, namely `__alltraps`. At
//! initialization in [`init()`], we set the trap entry CSR (`stvec` on RISC-V,
//! `eentry` on LoongArch) to point to it.
//!
//! All traps go through `__alltraps`, which is defined in `trap.S`. The
//! assembly language code does just enough work restore the kernel space
//! context, ensuring that Rust code safely runs, and transfers control to
//! [`trap_handler()`].
//!
//! It then calls different functionality based on what exactly the exception
//! was. For example, timer interrupts trigger task preemption, and syscalls go
//! to [`syscall()`].

mod context;

