#[cfg(target_arch = "loongarch64")]
/// Enable timer interrupt (LoongArch ECFG LIE only, like RISC-V `sie.STIE`).
///
/// Does not set `CRMD.IE`; global interrupt enable is restored on `ertn` via
/// TrapContext PRMD (`PIE=1`) when entering user mode.
pub fn enable_timer_interrupt() {
    // TI: ESTAT.IS[11]; enable its LIE bit only.
    let timer_lie =
        LineBasedInterrupt::from_bits_truncate(1 << LaInterrupt::Timer as usize);
    let lie = ecfg::read().lie().union(timer_lie);
    ecfg::set_lie(lie);
}
