//! Implementation of [`TrapContext`]
#[cfg(target_arch = "riscv64")]
use riscv::register::sstatus::{self, Sstatus, SPP};

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[cfg(target_arch = "loongarch64")]
/// Trap context saved on user/kernel trap entry (LoongArch).
pub struct TrapContext {
    /// General-purpose registers r0–r31
    pub x: [usize; 32],
    /// PRMD snapshot (raw CSR value)
    pub prmd: usize,
    /// ERA / return PC (raw CSR value)
    pub era: usize,
    /// Kernel stack pointer for this task
    pub kernel_sp: usize,
    /// Virtual address of trap handler entry in kernel
    pub trap_handler: usize,
    /// FPU registers f0-f31 + fcsr0 (lazy save/restore)
    pub fpu_regs: [u64; 33],
}

#[cfg(target_arch = "riscv64")]
#[derive(Debug, Clone, Copy)]
/// trap context structure containing sstatus, sepc and registers
pub struct TrapContext {
    /// General-Purpose Register x0-31
    pub x: [usize; 32],
    /// Supervisor Status Register
    pub sstatus: Sstatus,
    /// Supervisor Exception Program Counter
    pub sepc: usize,
    /// Token of kernel address space
    pub kernel_satp: usize,
    /// Kernel stack pointer of the current application
    pub kernel_sp: usize,
    /// Virtual address of trap handler entry point in kernel
    pub trap_handler: usize,
    /// FPU registers f0-f31 + fcsr (lazy save/restore, only when FS==Dirty)
    pub fpu_regs: [u64; 33],
}

#[cfg(target_arch = "riscv64")]
impl TrapContext {
    /// put the sp(stack pointer) into x\[2\] field of TrapContext
    pub fn set_sp(&mut self, sp: usize) {
        self.x[2] = sp;
    }
    /// init the trap context of an application
    pub fn app_init_context(
        entry: usize,
        sp: usize,
        kernel_satp: usize,
        kernel_sp: usize,
        trap_handler: usize,
    ) -> Self {
        let mut sstatus = sstatus::read();
        // set CPU privilege to User after trapping back
        sstatus.set_spp(SPP::User);
        // FS=Initial (0b01): 声称 FPU 寄存器全是初始值，硬件在首次 FPU 指令时自动转为 Dirty
        // riscv crate 版本可能没有 set_fs 方法，直接操作 raw bits
        let bits = sstatus.bits();
        let bits = (bits & !(0b11 << 13)) | (0b01 << 13);
        sstatus = unsafe { core::mem::transmute(bits) };
        let mut cx = Self {
            x: [0; 32],
            sstatus,
            sepc: entry,
            kernel_satp,
            kernel_sp,
            trap_handler,
            fpu_regs: [0; 33],
        };
        cx.set_sp(sp);
        cx
    }
}

#[cfg(target_arch = "loongarch64")]
impl TrapContext {
    /// put the sp(stack pointer) into r3 field of TrapContext
    pub fn set_sp(&mut self, sp: usize) {
        self.x[3] = sp;
    }
    /// init the trap context of an application
    pub fn app_init_context(
        entry: usize,
        sp: usize,
        _kernel_satp: usize,
        kernel_sp: usize,
        trap_handler: usize,
    ) -> Self {
        // PRMD snapshot for first ERTN to user (do not read/write live CSRs here).
        // [1:0] PPLV=3, [2] PIE=1, [3] PWE=1 — restored into CRMD on ERTN.
        const PRMD_PPLV: usize = 3;
        const PRMD_PIE: usize = 1 << 2;
        const PRMD_PWE: usize = 1 << 3;
        let prmd = PRMD_PPLV | PRMD_PIE | PRMD_PWE;
        let kernel_sp = kernel_sp - 32;
        // let sp = sp - 32; // 用户栈按 ABI 指向 argc，不应减 32
        let mut cx = Self {
            x: [0; 32],
            prmd,
            era: entry,
            kernel_sp,
            trap_handler,
            fpu_regs: [0; 33],
        };
        cx.set_sp(sp);
        cx
    }
}

