        let task = current_task().unwrap();
        let is_fpu_owner = FPU_OWNER.exclusive_access()
            .as_ref()
            .and_then(|w| w.upgrade())
            .map_or(false, |owner| Arc::ptr_eq(&owner, &task));
        if !is_fpu_owner {
            euen::set_fpe(false);
        }
    }
    trap_return();
}

/// trap handler (RISC-V)
#[cfg(target_arch = "riscv64")]
#[no_mangle]
pub fn trap_handler() -> ! {
    set_kernel_trap_entry();
    let scause = scause::read();
    let stval = stval::read();
    // trace!("into {:?}", scause.cause());
    let mut now = get_time();
    {
        let process = current_process();
        let mut inner = process.inner_exclusive_access();
        inner.utime += now - inner.change_time;
        inner.change_time = now;
        drop(inner);
    }
    let mut in_syscall = false;
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            {
                let task = current_task().unwrap();
                let mut inner = task.inner_exclusive_access();
                inner.in_syscall = true;
                in_syscall = true;
            }
            let mut cx = current_trap_cx();
            cx.sepc += 4;
            let syscall_id = cx.x[17];
            let result = syscall(
                syscall_id,
                [cx.x[10], cx.x[11], cx.x[12], cx.x[13], cx.x[14], cx.x[15]],
            );
            cx = current_trap_cx();

            cx = current_trap_cx();
            cx.x[10] = result as usize;
        }
        Trap::Exception(Exception::LoadPageFault)
        | Trap::Exception(Exception::StorePageFault) => {
            let cx = current_trap_cx();
            // workaround: glibc busybox 退出时 s1 被错误设为 fd=2(stderr),
            // 导致 jalr s1 跳转到 0x2，触发 InstructionPageFault
            // 这是用户态 glibc bug，进程实际已完成工作，直接 exit(0)
            if stval <= 0xF {
                exit_current_and_run_next(0);
            }
            let fault_va = stval;
            let is_write = matches!(scause.cause(), Trap::Exception(Exception::StorePageFault));
            let process = current_process();
            let mut inner = process.inner_exclusive_access();
            if inner.memory_set.handle_page_fault(VirtAddr::from(fault_va), is_write).is_ok() {
                drop(inner);
            } else {
                drop(inner);
                report_sigsegv(cx, stval, scause);
                current_add_signal(SignalFlags::SIGSEGV);
            }
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault) => {
            let cx = current_trap_cx();
            // workaround: glibc busybox 退出时 s1 被错误设为 fd=2(stderr),
            // 导致跳转到低地址，触发 fault
            if stval <= 0xF {
                exit_current_and_run_next(0);
            }
            report_sigsegv(cx, stval, scause);
            current_add_signal(SignalFlags::SIGSEGV);
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            let ill_pc = current_trap_cx().sepc;
            error!(
                "[SIGILL] pid={} bad_addr=0x{:x} sepc=0x{:x}",
                current_task().unwrap().process.upgrade().unwrap().getpid(),
                stval,
                ill_pc,
            );
            current_add_signal(SignalFlags::SIGILL);
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            set_next_trigger();
            check_timer();
            let current_task = current_task().unwrap();
            let mut inner = current_task.inner_exclusive_access();
            let mut need_schedule = false;
            let highest_ready_prio = TASK_MANAGER.exclusive_access().peek_highest_rt_priority();
            const SCHED_FIFO: usize = 1;
            const SCHED_RR: usize = 2;
            match inner.policy {
                SCHED_FIFO => {
                    if highest_ready_prio > inner.priority as i32 {
                        need_schedule = true;
                    }
                }
                SCHED_RR => {
                    if inner.time_slice > 0 {
                        inner.time_slice -= 1;
                    }
                    if inner.time_slice == 0 {
                        inner.time_slice = 1;
                        need_schedule = true;
                    } else if highest_ready_prio > inner.priority as i32 {
                        need_schedule = true;
                    }
                }
                // _ => need_schedule = true,
                _ => {
                    if inner.time_slice > 0 {
                        inner.time_slice -= 1;
                    }
                    if inner.time_slice == 0 {
                        inner.time_slice = 1;
                        need_schedule = true;
                    } else if highest_ready_prio > inner.priority as i32 {
                        need_schedule = true;
                    }
                }
            }
            drop(inner);
            if need_schedule {
                suspend_current_and_run_next();
            }
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    }
    let signal_delivered = deliver_signal_to_user();
    if !signal_delivered {
        let cx = current_trap_cx();
        #[cfg(target_arch = "riscv64")]
        let a0_val = cx.x[10];
        #[cfg(target_arch = "loongarch64")]
        let a0_val = cx.x[4];
        if in_syscall == true && a0_val == -512 as isize as usize {
            // 没有自定义处理函数时，Linux 默认也是将其转成 -EINTR 返回给用户态
            #[cfg(target_arch = "riscv64")]
            { cx.x[10] = -4 as isize as usize; }
            #[cfg(target_arch = "loongarch64")]
            { cx.x[4] = -4 as isize as usize; }
        }
        if let Some((errno, _msg)) = check_signals_of_current() {
            exit_group_current_and_run_next(errno);
        }
    }
    now = get_time();
    {
        let process = current_process();
        let mut inner = process.inner_exclusive_access();
        inner.stime += now - inner.change_time;
        inner.change_time = now;
        drop(inner);
    }
    {
        let task = current_task().unwrap();
        let mut inner = task.inner_exclusive_access();
        inner.in_syscall = false;
    }
    trap_return();
}

/// return to user space
#[no_mangle]
pub fn trap_return() -> ! {
    set_user_trap_entry();
    extern "C" {
        fn __restore();
    }

    #[cfg(target_arch = "loongarch64")]
    {
        let user_token = current_user_token() << PAGE_SIZE_BITS;

        let trap_cx_pa = current_trap_cx_pa();
        let restore_va = __restore as usize;
        unsafe {
            asm!(
                "ibar 0",
                "jirl $zero, {restore_va}, 0",
                restore_va = in(reg) restore_va,
                in("$r4") trap_cx_pa,
                in("$r5") user_token,
                options(noreturn)
            );
        }
    }
    #[cfg(target_arch = "riscv64")]
    {
        let user_token = current_user_token();
        extern "C" {
            fn __alltraps();
        }
        let trap_cx_user_va = current_trap_cx_user_va();
        let restore_va = __restore as usize - __alltraps as usize + TRAMPOLINE;
        unsafe {
            asm!(
                "fence.i",
                "jr {restore_va}",
                restore_va = in(reg) restore_va,
                in("x10") trap_cx_user_va,
                in("x11") user_token,
                options(noreturn)
            );
        }
    }
}

