    use riscv::register::sepc;
    panic!(
        "stval = {:#x}, sepc = {:#x}, a trap {:?} from kernel!",
        stval::read(),
        sepc::read(),
        scause::read().cause()
    );
}

#[cfg(target_arch = "loongarch64")]
/// LoongArch exception code to short name. Only for debug.
fn la_exception_name(ecode: usize, esub: usize) -> &'static str {
    match ecode {
        1 => "INT",
        2 => "PIL",
        3 => "PIS",
        4 => "PIF",
        5 => "PME",

        5 => "PME",
        6 => "PNR",
        7 => "PNX",
        8 if esub == 0 => "ADEF",
        8 => "ADEM",
        9 if esub == 0 => "ALE-Fetch",
        9 => "ALE-Memory",
        10 => "SYS",
        11 => "BRK",
        12 => "INE",
        13 => "IPE",
        15 => "FPU",
        _ => "UNKNOWN",
    }
}

#[cfg(target_arch = "loongarch64")]
/// Read PGDL/PGDH/PRMD CSRs via `csrrd` (CSR must be immediate). Only for debug.
#[inline]
fn la_read_pgdl_pgdh_prmd() -> (usize, usize, usize) {
    let pgdl: usize;
    let pgdh: usize;
    let prmd: usize;
    unsafe {
        asm!(
            "csrrd {pgdl}, 0x19",
            "csrrd {pgdh}, 0x1a",
            "csrrd {prmd}, 0x1",
            pgdl = out(reg) pgdl,
            pgdh = out(reg) pgdh,
            prmd = out(reg) prmd,
            options(nostack)
        );
    }
    (pgdl, pgdh, prmd)
}

#[cfg(target_arch = "loongarch64")]
/// Handle trap from kernel mode (LoongArch).
///
/// Logs extended diagnostics via `[KernelTrap]` then panics. Only for debug.
#[no_mangle]
pub fn trap_from_kernel() -> ! {
    use loongArch64::register::era;

    let estat = estat::read();
    let ecode = estat.ecode();
    let esub = estat.esubcode();
    let badv = la_badv(badv::read());
    let era_pc = la_era(era::read());
    let era_pa = dmw_to_phys(era_pc);
    let badi_insn = la_badi(badi::read()) as u32;
    let insn_at_era = unsafe { core::ptr::read_volatile(era_pc as *const u32) };

    let (pgdl_csr, pgdh_csr, prmd_csr) = la_read_pgdl_pgdh_prmd();
    let k_token = kernel_token();
    let u_token = current_user_token();
    let user_pg = u_token << PAGE_SIZE_BITS;

    let va = VirtAddr::from(badv);
    let u_pt = PageTable::from_token(u_token);
    let u_sw_pte = u_pt.translate(va.floor()).map(|pte| pte.bits);
    let u_sw_pa = u_pt.translate_va(va).map(|pa| pa.0);
    let u_walk = u_pt.debug_walk(va.floor());

    let k_pt = PageTable::from_token(k_token);
    let k_sw_pte = k_pt.translate(va.floor()).map(|pte| pte.bits);
    let k_walk = k_pt.debug_walk(va.floor());

    let (pid, exe) = {
        let p = current_process();
        let inner = p.inner_exclusive_access();
        (p.getpid(), inner.exe_path.clone())
    };

    error!(
        "[KernelTrap] {} pid={} exe={} \
         badv=0x{:x} era=0x{:x} era_pa=0x{:x} badi=0x{:08x} insn@era=0x{:08x} \
         ecode={} esub={} is=0x{:x} \
         crmd={:?} prmd=0x{:x} \
         pgdl_csr=0x{:x} pgdh_csr=0x{:x} pgd={:?} \
         kernel_token=0x{:x} user_token=0x{:x} user_pg=0x{:x} \
         pgdl_eq_pgdh={} csr_eq_user_pg={} \
         user_walk={} user_sw_pte={:#x} user_sw_pa={:#x} \
         kernel_walk={} kernel_sw_pte={:#x}",
        la_exception_name(ecode, esub),
        pid,
        exe,
        badv,
        era_pc,
        era_pa,
        badi_insn,
        insn_at_era,
        ecode,
        esub,
        estat.is(),
        crmd::read(),
        prmd_csr,
        pgdl_csr,
        pgdh_csr,
        pgd::read(),
        k_token,
        u_token,
        user_pg,
        pgdl_csr == pgdh_csr,
        pgdl_csr == user_pg,
        u_walk,
        u_sw_pte.unwrap_or(0),
        u_sw_pa.unwrap_or(0),
        k_walk,
        k_sw_pte.unwrap_or(0),
    );

    panic!(
        "kernel trap: {} badv=0x{:x} era=0x{:x} (pa=0x{:x}) — see [KernelTrap] above",
        la_exception_name(ecode, esub),
        badv,
        era_pc,
        era_pa,
    );
}


#[cfg(target_arch = "riscv64")]
/// 打印详细的 SIGSEGV 诊断信息（寄存器、内存映射、指令 dump、栈回溯）
fn report_sigsegv(cx: &TrapContext, stval: usize, _scause: scause::Scause) {
    use crate::mm::{VirtPageNum, VirtAddr, translated_ref};
    let process = current_process();
    let inner = process.inner_exclusive_access();
    let vpn: VirtPageNum = VirtAddr(stval).floor();
    let (pte_bits, area_info) = match inner.memory_set.translate(vpn) {
        Some(pte) => {
            let area_desc = inner.memory_set.areas.iter()
                .find(|a| a.vpn_range.get_start() <= vpn && vpn < a.vpn_range.get_end())
                .map(|a| {
                    let start = a.vpn_range.get_start();
                    let end = a.vpn_range.get_end();
                    alloc::format!("vpn=[0x{:x},0x{:x}) perm=0x{:x}", start.0, end.0, a.map_perm.bits())
                })
                .unwrap_or_else(|| alloc::string::String::from("none"));
            (pte.bits as isize, area_desc)
        }
        None => (-1, alloc::string::String::from("unmapped")),
    };
    let trap_pc = cx.sepc;
    let sp = cx.x[2];
    let sepc_vpn: VirtPageNum = VirtAddr(trap_pc).floor();
    let sepc_pte = inner.memory_set.translate(sepc_vpn).map(|p| p.bits as isize).unwrap_or(-1);
    let token = inner.memory_set.token();
    let exe_path = inner.exe_path.clone();
    let ra_vpn: VirtPageNum = VirtAddr(cx.x[1]).floor();
    let ra_area = inner.memory_set.areas.iter()
        .find(|a| a.vpn_range.get_start() <= ra_vpn && ra_vpn < a.vpn_range.get_end())
        .map(|a| {
            let start: usize = a.vpn_range.get_start().into();
            let end: usize = a.vpn_range.get_end().into();
            alloc::format!("vpn=[0x{:x},0x{:x}) va=[0x{:x},0x{:x}) perm=0x{:x}", start, end, start << 12, end << 12, a.map_perm.bits())
        })
        .unwrap_or_else(|| alloc::string::String::from("none"));
    let mut areas_str = alloc::string::String::new();
    for a in inner.memory_set.areas.iter().take(16) {
        let start: usize = a.vpn_range.get_start().into();
        let end: usize = a.vpn_range.get_end().into();
        use core::fmt::Write;
        let _ = write!(areas_str, " [0x{:x},0x{:x})", start << 12, end << 12);
    }
    drop(inner);
    error!(
        "[SIGSEGV] pid={} name={} {:?} bad_addr=0x{:x} sepc=0x{:x} ra=0x{:x} sp=0x{:x} pte=0x{:x} area={} sepc_pte=0x{:x}",
        current_task().unwrap().process.upgrade().unwrap().getpid(),
        current_task().unwrap().process.upgrade().unwrap().inner_exclusive_access().name,
        _scause.cause(),
        stval,
        trap_pc,
        cx.x[1],
        sp,
        pte_bits,
        area_info,
        sepc_pte,
    );
    error!("[SIGSEGV-EXE] exe_path={}", exe_path);
    error!("[SIGSEGV-MAP] ra_area={}", ra_area);
    if !areas_str.is_empty() {
        error!("[SIGSEGV-MAP] all_areas:{}", areas_str);
    }
    error!(
        "[SIGSEGV-REG] ra=0x{:x} sp=0x{:x} gp=0x{:x} tp=0x{:x}",
        cx.x[1], cx.x[2], cx.x[3], cx.x[4],
    );
    error!(
        "[SIGSEGV-REG] t0=0x{:x} t1=0x{:x} t2=0x{:x} fp=0x{:x}",
        cx.x[5], cx.x[6], cx.x[7], cx.x[8],
    );
    error!(
        "[SIGSEGV-REG] a0=0x{:x} a1=0x{:x} a2=0x{:x} a3=0x{:x}",
        cx.x[10], cx.x[11], cx.x[12], cx.x[13],
    );
    error!(
        "[SIGSEGV-REG] a4=0x{:x} a5=0x{:x} a6=0x{:x} a7=0x{:x}",
        cx.x[14], cx.x[15], cx.x[16], cx.x[17],
    );

    );
    error!(
        "[SIGSEGV-REG] t3=0x{:x} t4=0x{:x} t5=0x{:x} t6=0x{:x}",
        cx.x[28], cx.x[29], cx.x[30], cx.x[31],
    );
    error!(
        "[SIGSEGV-REG] s1=0x{:x} s2=0x{:x} s3=0x{:x} s4=0x{:x}",
        cx.x[9], cx.x[18], cx.x[19], cx.x[20],
    );
    error!(
        "[SIGSEGV-REG] s5=0x{:x} s6=0x{:x} s7=0x{:x} s8=0x{:x}",
        cx.x[21], cx.x[22], cx.x[23], cx.x[24],
    );
    error!(
        "[SIGSEGV-REG] s9=0x{:x} s10=0x{:x} s11=0x{:x}",
        cx.x[25], cx.x[26], cx.x[27],
    );
    // 指令字 dump
    let ra = cx.x[1];
    let insns: [u32; 4] = [
        *translated_ref(token, (ra.wrapping_sub(8)) as *const u32),
        *translated_ref(token, (ra.wrapping_sub(4)) as *const u32),
        *translated_ref(token, ra as *const u32),
        *translated_ref(token, (ra.wrapping_add(4)) as *const u32),
    ];
    error!(
        "[SIGSEGV-CODE] ra-8=0x{:08x} ra-4=0x{:08x} ra=0x{:08x} ra+4=0x{:08x}",
        insns[0], insns[1], insns[2], insns[3],
    );
    let hw: [u16; 8] = [
        *translated_ref(token, (ra.wrapping_sub(8)) as *const u16),
        *translated_ref(token, (ra.wrapping_sub(6)) as *const u16),
        *translated_ref(token, (ra.wrapping_sub(4)) as *const u16),
        *translated_ref(token, (ra.wrapping_sub(2)) as *const u16),
        *translated_ref(token, ra as *const u16),
        *translated_ref(token, (ra.wrapping_add(2)) as *const u16),
        *translated_ref(token, (ra.wrapping_add(4)) as *const u16),
        *translated_ref(token, (ra.wrapping_add(6)) as *const u16),
    ];
    error!(
        "[SIGSEGV-CHW] ra-8=0x{:04x} ra-6=0x{:04x} ra-4=0x{:04x} ra-2=0x{:04x} ra=0x{:04x} ra+2=0x{:04x} ra+4=0x{:04x} ra+6=0x{:04x}",
        hw[0], hw[1], hw[2], hw[3], hw[4], hw[5], hw[6], hw[7],
    );
    let mut wide_code = alloc::string::String::new();
    use core::fmt::Write;
    for offset in (-16..=16).step_by(2) {
        let addr = (ra as isize + offset) as usize;
        let h = *translated_ref(token, addr as *const u16);
        let _ = write!(wide_code, " {:+}=0x{:04x}", offset, h);
    }
    if !wide_code.is_empty() {
        error!("[SIGSEGV-WIDE]{}", wide_code);
    }
    let mut stack_dump = alloc::string::String::new();
    for offset in (-256..=248).step_by(8) {
        let addr = (sp as isize + offset) as usize;
        let val = *translated_ref(token, addr as *const usize);
        if val != 0 && (val >= 0x10000 && val <= 0x1b1000 || val == 0x2 || offset >= -64 && offset <= 64) {
            let tag = if val == 0x2 { " ***S1=0x2***" } else if val >= 0x10000 && val <= 0x1b1000 { " (code)" } else { "" };
            let _ = write!(stack_dump, " [{:+}]=0x{:016x}{}", offset, val, tag);
        }
    }
    if !stack_dump.is_empty() {
        error!("[SIGSEGV-STK] sp=0x{:x}{}", sp, stack_dump);
    }
    // 搜索 0x2
    let mut found_0x2 = alloc::vec::Vec::new();
    for offset in (-8192isize..0).step_by(8) {
        let addr = (sp as isize + offset) as usize;
        let val = *translated_ref(token, addr as *const usize);
        if val == 0x2 {
            found_0x2.push(offset);
        }
    }
    if !found_0x2.is_empty() {
        error!("[SIGSEGV-SEARCH] found 0x2 at stack offsets: {:?}", found_0x2);
    }
    // 栈回溯
    let mut fp = cx.x[8];
    let mut depth = 0;
    error!("[SIGSEGV-BT] depth=0 ra=0x{:x} (crash site, pc=0x{:x})", cx.x[1], trap_pc);
    loop {
        if fp < sp || fp + core::mem::size_of::<usize>() * 2 > sp + 0x200000 || depth >= 8 {
            break;
        }
        let saved_ra = *translated_ref(token, (fp.wrapping_sub(core::mem::size_of::<usize>())) as *const usize);
        let next_fp = *translated_ref(token, fp as *const usize);
        if saved_ra == 0 || next_fp == 0 || next_fp <= fp {
            break;
        }
        depth += 1;
        error!("[SIGSEGV-BT] depth={} ra=0x{:x} fp=0x{:x}", depth, saved_ra, next_fp);
        fp = next_fp;
    }
}
#[cfg(target_arch = "loongarch64")]
/// Clear the FPU owner if `task` was the current FPU owner.
/// Called when a process/thread exits.
pub fn clear_fpu_owner_if(task_weak: &Weak<TaskControlBlock>) {
    let mut fpu_owner = FPU_OWNER.exclusive_access();
    let should_clear = match fpu_owner.as_ref() {
        None => false,
        Some(owner) => {
            let owner_ptr = owner.as_ptr() as *const ();
            let task_ptr = task_weak.as_ptr() as *const ();
            owner_ptr == task_ptr
        }
    };
    if should_clear {
        *fpu_owner = None;
    }
}

pub use context::TrapContext;

//! Types related to task management & Functions for completely changing TCB

use super::id::TaskUserRes;
use super::{alloc_global_tid, kstack_alloc, KernelStack, ProcessControlBlock, TaskContext};
use crate::task::SignalFlags;
use crate::trap::TrapContext;
use crate::{mm::PhysPageNum, sync::UPSafeCell};
use alloc::sync::{Arc, Weak};
use alloc::vec::Vec;
use core::cell::RefMut;

/// Task control block structure
pub struct TaskControlBlock {
    /// immutable
    pub process: Weak<ProcessControlBlock>,
    /// Kernel stack corresponding to PID
    pub kstack: KernelStack,
    /// Global thread id (for gettid)
    pub tid: usize,
    /// mutable
    inner: UPSafeCell<TaskControlBlockInner>,
}

impl TaskControlBlock {
    /// Get the mutable reference of the inner TCB
    pub fn inner_exclusive_access(&self) -> RefMut<'_, TaskControlBlockInner> {
        self.inner.exclusive_access()
    }
    /// Try to get the mutable reference of the inner TCB, return None if already borrowed
    pub fn try_inner_exclusive_access(&self) -> Option<RefMut<'_, TaskControlBlockInner>> {
        self.inner.try_exclusive_access()
    }
    /// Get the address of app's page table
    pub fn get_user_token(&self) -> usize {
        let process = self.process.upgrade().unwrap();
        let inner = process.inner_exclusive_access();
        inner.memory_set.token()
    }
    /// Whether there exists signals to handle
    pub fn has_pending_signals(&self) -> bool {
        let inner = self.inner.exclusive_access();
        inner.signals.bits() & !inner.signals_mask.bits() != 0
    }
}

pub struct TaskControlBlockInner {
    pub res: Option<TaskUserRes>,
    /// The physical page number of the frame where the trap context is placed
    pub trap_cx_ppn: PhysPageNum,
    /// Save task context
    pub task_cx: TaskContext,

    /// Maintain the execution status of the current process
    pub task_status: TaskStatus,
    /// It is set when active exit or execution error occurs
    pub exit_code: Option<i32>,

    /// Length the task has been running, used for scheduling
    pub stride: usize,
    /// Stride value, used for scheduling
    pub pass: usize,
    /// Schedule policy
    pub policy: usize,
    /// Priority for real-time scheduling, higher value means higher priority
    pub priority: usize,
    /// RR schedule time slice
    pub time_slice: usize,

    /// See sys_set_tid_address
    pub tid_clear_address: Option<usize>,

    /// Robust list head pointer
    pub robust_list_head: usize,
    /// Robust list length
    pub robust_list_len: usize,

    /// Signals to be handled
    pub signals: SignalFlags,
    /// Signals mask
    pub signals_mask: SignalFlags,
    /// effective signals waiting number
    pub pending_signals_count: usize,
    /// 是否处于系统调用中断的处理中
    pub in_syscall: bool,
    /// 信号递送时保存 trap context 的用户栈地址（用于 sigreturn 恢复，栈结构支持嵌套）
    pub saved_trap_cx_addrs: Vec<usize>,
    /// 用于备份系统调用入口时
    pub orig_a0: usize,
}

impl TaskControlBlockInner {
    pub fn get_trap_cx(&self) -> &'static mut TrapContext {
        self.trap_cx_ppn.get_mut()
    }

    #[allow(unused)]
    fn get_status(&self) -> TaskStatus {
        self.task_status
    }
}

impl TaskControlBlock {
    /// Create a new task
    pub fn new(
        process: Arc<ProcessControlBlock>,
        ustack_base: usize,
        alloc_user_stack: bool,
        alloc_trap_cx: bool,
    ) -> Self {
        let res = TaskUserRes::new(Arc::clone(&process), ustack_base, alloc_user_stack, alloc_trap_cx);
        let trap_cx_ppn = res.trap_cx_ppn();
        let kstack = kstack_alloc();
        let kstack_top = {
            #[cfg(target_arch = "riscv64")]
            {
                kstack.get_top()
            }
            #[cfg(target_arch = "loongarch64")]
            {
                kstack.get_top() - 32
            }
        };
        Self {
            process: Arc::downgrade(&process),
            kstack,
            tid: alloc_global_tid(),
            inner: unsafe {
                UPSafeCell::new(TaskControlBlockInner {
                    res: Some(res),
                    trap_cx_ppn,
                    task_cx: TaskContext::goto_trap_return(kstack_top),
                    task_status: TaskStatus::Ready,
                    exit_code: None,
                    stride: 0,
                    pass: 1,
                    policy: 0,
                    priority: 0,
                    time_slice: 1,
                    tid_clear_address: None,
                    robust_list_head: 0,
                    robust_list_len: 0,
                    signals: SignalFlags::empty(),
                    signals_mask: SignalFlags::empty(),
                    pending_signals_count: 0,
                    in_syscall: false,
                    saved_trap_cx_addrs: Vec::new(),
                    orig_a0: 0,
                })
            },
        }
    }
}

