/// A circular buffer
pub struct KernelLogBuffer {
    /// buffer
    pub buffer: [u8; LOG_BUFFER_SIZE],
    /// head index
    pub head: usize,
    /// tail index
    pub tail: usize,
    /// total bytes written since the system booted
    pub total_written: usize,
}

impl Write for KernelLogBuffer {
    fn write_str(&mut self, s: &str) -> core::fmt::Result {
        for &byte in s.as_bytes() {
            self.buffer[self.head] = byte;
            self.head = (self.head + 1) % LOG_BUFFER_SIZE;
            self.total_written += 1;
            if self.head == self.tail {
                self.tail = (self.tail + 1) % LOG_BUFFER_SIZE;
            }
        }
        Ok(())
    }
}

/// Write formatted string to kernel log buffer
pub fn klog_write_args(args: core::fmt::Arguments) {
    let mut klog = KLOG.lock();
    let _ = klog.write_fmt(args);
}

