/// 共享内存管理器
pub struct ShmManager {
    /// 段s
    pub segments: Vec<Option<ShmSegment>>,
    /// 用于分配下一个 id
    pub next_id: usize,
}

impl ShmManager {
    /// new 一个共享内存段
    pub fn new() -> Self {
        let mut segments = Vec::with_capacity(MAX_SHM_SEGMENTS);
        for _ in 0..MAX_SHM_SEGMENTS {
            segments.push(None);
        }
        Self {
            segments,
            next_id: 0,
        }
    }
    /// find by key
    pub fn find_by_key(&self, key: usize) -> Option<usize> {
        for (i, seg) in self.segments.iter().enumerate() {
            if let Some(ref seg) = seg {
                if seg.key == key && !seg.deleted {
                    return Some(i);
                }
            }
        }
        None
    }
    /// find by id
    pub fn find_by_id(&self, shmid: usize) -> Option<usize> {
        for (i, seg) in self.segments.iter().enumerate() {
            if let Some(ref seg) = seg {
                if seg.id == shmid && !seg.deleted {
                    return Some(i);
                }
            }
        }
        None
    }
    /// create a shm
    pub fn create(&mut self, key: usize, size: usize, shmflg: u32) -> isize {
        // 找一个空闲 slot
        let idx = match self.segments.iter().position(|s| s.is_none()) {
            Some(i) => i,
            None => return -ENOSPC,
        };
        // 分配物理帧（按 PAGE_SIZE 向上取整）
        let page_count = (size + PAGE_SIZE - 1) / PAGE_SIZE;
        let mut frames = Vec::with_capacity(page_count);
        for _ in 0..page_count {
            match frame_alloc() {
                Some(f) => frames.push(Arc::new(f)),
                None => {
                    // 分配失败，之前已分配的帧会在 drop 时由 Arc<FrameTracker> 回收
                    return -ENOMEM;
                }
            }
        }
        let id = self.next_id;
        self.next_id += 1;
        let process = current_process();
        let inner = process.inner_exclusive_access();
        let uid = inner.cred.euid;
        let gid = inner.cred.egid;
        let pid = process.getpid();
        let mode = (shmflg & 0o777) as u16;
        drop(inner);
        let now = get_time() as i64;
        self.segments[idx] = Some(ShmSegment {
            id,
            key,
            size,
            frames,
            nattch: 0,
            attach_addr: 0,
            cuid: uid,
            cgid: gid,
            uid,
            gid,
            cpid: pid,
            lpid: 0,
            mode,
            deleted: false,
            atime: 0,
            dtime: 0,
            ctime: now,
        });
        id as isize
    }
}

