//! Implementation of [`TaskManager`]
//!
//! It is only used to manage processes and schedule process based on ready queue.
//! Other CPU process monitoring functions are in Processor.

use super::{ProcessControlBlock, TaskControlBlock, TaskStatus};
use crate::sync::UPSafeCell;
use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::Arc;
use alloc::vec::Vec;
use core::cmp::Reverse;
use lazy_static::*;

#[derive(Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum SchedKey {
    RealTime(Reverse<isize>),
    Normal(Reverse<isize>),
}

///A array of `TaskControlBlock` that is thread-safe
pub struct TaskManager {
    ready_queue: BTreeMap<SchedKey, VecDeque<Arc<TaskControlBlock>>>,

    /// The stopping task, leave a reference so that the kernel stack will not be recycled when switching tasks
    stop_task: Option<Arc<TaskControlBlock>>,
}

/// A simple FIFO scheduler.
impl TaskManager {
    ///Creat an empty TaskManager
    pub fn new() -> Self {
        Self {
            ready_queue: BTreeMap::new(),
            stop_task: None,
        }
    }
    /// Add process back to ready queue
    pub fn add(&mut self, task: Arc<TaskControlBlock>) {
        const SCHED_FIFO: usize = 1;
        const SCHED_RR: usize = 2;
        let (policy, priority, _stride) = {
            let inner = task.inner_exclusive_access();
            (inner.policy, inner.priority as isize, inner.stride)
        };
        let key = if policy == SCHED_FIFO || policy == SCHED_RR {
            SchedKey::RealTime(Reverse(priority))
        } else {
            SchedKey::Normal(Reverse(priority))
        };
        self.ready_queue
            .entry(key)
            .or_insert_with(VecDeque::new)
            .push_back(task);
    }
    /// Take a process out of the ready queue
    /// Fetch the process with the lowest stride value, and update the stride value of the process
    pub fn fetch(&mut self) -> Option<Arc<TaskControlBlock>> {
        let mut entry = self.ready_queue.first_entry()?;
        let queue = entry.get_mut();
        let task = queue.pop_front().unwrap();
        if queue.is_empty() {
            entry.remove();
        }
        const SCHED_FIFO: usize = 1;
        const SCHED_RR: usize = 2;
        let policy = task.inner_exclusive_access().policy;
        if policy != SCHED_FIFO && policy != SCHED_RR {
            let mut inner = task.inner_exclusive_access();
            inner.stride += inner.pass;
        }
        Some(task)
    }
    pub fn remove(&mut self, task: Arc<TaskControlBlock>) {
        const SCHED_FIFO: usize = 1;
        const SCHED_RR: usize = 2;
        let key = {
            let inner = task.inner_exclusive_access();
            if inner.policy == SCHED_FIFO || inner.policy == SCHED_RR {
                SchedKey::RealTime(Reverse(inner.priority as isize))
            } else {
                SchedKey::Normal(Reverse(inner.priority as isize))
            }
        };
        if let Some(queue) = self.ready_queue.get_mut(&key) {
            if let Some(pos) = queue.iter().position(|t| Arc::ptr_eq(t, &task)) {
                queue.remove(pos);
                if queue.is_empty() {
                    self.ready_queue.remove(&key);
                }
            }
        }
    }
    /// Add a task to stopping task
    pub fn add_stop(&mut self, task: Arc<TaskControlBlock>) {
        // NOTE: as the last stopping task has completely stopped (not
        // using kernel stack any more, at least in the single-core
        // case) so that we can simply replace it;
        self.stop_task = Some(task);
    }
    /// Peek the highest priority of real-time tasks, return -1 if no real-time task is ready
    pub fn peek_highest_rt_priority(&self) -> i32 {
        match self.ready_queue.first_key_value() {
            Some((SchedKey::RealTime(Reverse(prio)), _)) => *prio as i32,
            _ => -1,
        }
    }
}

