/// Add a task to ready queue
pub fn add_task(task: Arc<TaskControlBlock>) {
    //trace!("kernel: TaskManager::add_task");
    TASK_MANAGER.exclusive_access().add(task);
}

/// Wake up a task
pub fn wakeup_task(task: Arc<TaskControlBlock>) {
    trace!("kernel: TaskManager::wakeup_task global tid = {}", task.tid);
    let mut task_inner = task.inner_exclusive_access();
    if task_inner.task_status != TaskStatus::Blocked {
        return;
    }
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    add_task(task);
}

/// Remove a task from the ready queue
pub fn remove_task(task: Arc<TaskControlBlock>) {
    //trace!("kernel: TaskManager::remove_task");
    TASK_MANAGER.exclusive_access().remove(task);
}

/// Fetch a task out of the ready queue
pub fn fetch_task() -> Option<Arc<TaskControlBlock>> {
    //trace!("kernel: TaskManager::fetch_task");
    TASK_MANAGER.exclusive_access().fetch()
}

/// Set a task to stop-wait status, waiting for its kernel stack out of use.
pub fn add_stopping_task(task: Arc<TaskControlBlock>) {
    TASK_MANAGER.exclusive_access().add_stop(task);
}

/// Get process by pid
pub fn pid2process(pid: usize) -> Option<Arc<ProcessControlBlock>> {
    let map = PID2PCB.exclusive_access();
    map.get(&pid).map(Arc::clone)
}

/// Get process by pgid
pub fn pgid2processes(pgid: usize) -> Option<Vec<Arc<ProcessControlBlock>>> {
    let map = PID2PCB.exclusive_access();
    let mut procs = Vec::new();
    for (_, process) in map.iter() {
        // 这好像挺危险的, 谨慎使用
        if process.inner_exclusive_access().pgid as usize == pgid {
            procs.push(process.clone());
        }
    }
    if procs.is_empty() {
        return None;
    }
    else {
        return Some(procs);
    }
}

/// Get process by uid
pub fn uid2processes(uid: usize) -> Option<Vec<Arc<ProcessControlBlock>>> {
    let map = PID2PCB.exclusive_access();
    let mut procs = Vec::new();
    for (_, process) in map.iter() {
        // 这好像挺危险的, 谨慎使用
        if process.inner_exclusive_access().cred.uid as usize == uid {
            procs.push(process.clone());
        }
    }
    if procs.is_empty() {
        return None;
    }
    else {
        return Some(procs);
    }
}

/// Get task by tid
/// 暂时这么实现, 这种效率确实很低
pub fn tid2task(tid: usize) -> Option<Arc<TaskControlBlock>> {
    let map = PID2PCB.exclusive_access();
    for (_pid, process) in map.iter() {
        for task in &process.inner_exclusive_access().tasks {
            if let Some(task) = task {
                if task.tid == tid {
                    return Some(task.clone());
                }
            }
        }
    }
    None
}

/// Insert item(pid, pcb) into PID2PCB map (called by do_fork AND ProcessControlBlock::new)
pub fn insert_into_pid2process(pid: usize, process: Arc<ProcessControlBlock>) {
    PID2PCB.exclusive_access().insert(pid, process);
}

/// Remove item(pid, _some_pcb) from PDI2PCB map (called by exit_current_and_run_next)
pub fn remove_from_pid2process(pid: usize) {
    let mut map = PID2PCB.exclusive_access();
    if map.remove(&pid).is_none() {
        panic!("cannot find pid {} in pid2task!", pid);
    }
}

