    /// Translate a user-space byte buffer into kernel-mutable slices.
    /// If a page is not mapped (lazy allocation), it will be allocated on demand.
    /// `mode`: 0=read, 1=write.
    pub fn translated_byte_buffer(&mut self, ptr: *const u8, len: usize, mode: usize) -> Vec<&'static mut [u8]> {
        let mut start = ptr as usize;
        let end = start + len;
        let mut v = Vec::new();
        while start < end {
            let start_va = VirtAddr::from(start);
            let mut vpn = start_va.floor();
            let ppn = loop {
                match self.page_table.translate(vpn) {
                    Some(pte) => {
                        if !pte.is_valid() || !pte.user_accessible() {
                            // 尝试懒分配
                            let is_write = mode == 1;
                            if self.handle_page_fault(start_va, is_write).is_ok() {
                                continue; // 重试翻译
                            }
                            return Vec::new();
                        }
                        if mode == 0 && !pte.readable() {
                            return Vec::new();
                        }
                        if mode == 1 && !pte.writable() {
                            // COW: kernel writing to fork-shared page
                            if self.handle_cow_fault(start_va).is_ok() {
                                continue; // retry translation after COW resolved
                            }
                            return Vec::new();
                        }
                        break pte.ppn();
                    }
                    None => {
                        // 尝试懒分配
                        let is_write = mode == 1;
                        if self.handle_page_fault(start_va, is_write).is_ok() {
                            continue; // 重试翻译
                        }
                        return Vec::new();
                    }
                }
            };
            vpn.step();
            let mut end_va: VirtAddr = vpn.into();
            end_va = end_va.min(VirtAddr::from(end));
            if end_va.page_offset() == 0 {
                v.push(&mut ppn.get_bytes_array()[start_va.page_offset()..]);
            } else {
                v.push(&mut ppn.get_bytes_array()[start_va.page_offset()..end_va.page_offset()]);
            }
            start = end_va.into();
        }
        v
    }
    /// Translate a user-space null-terminated string into a Rust String.
    /// Returns None if any byte is unmapped or inaccessible.
    pub fn translated_str(&mut self, ptr: *const u8) -> Option<alloc::string::String> {
        if ptr.is_null() {
            return None;
        }
        let mut string = alloc::string::String::new();
        let mut pos = ptr as usize;
        loop {
            let page_offset = pos & (PAGE_SIZE - 1);
            let max_read = PAGE_SIZE - page_offset;
            let slices = self.translated_byte_buffer(pos as *const u8, max_read, 0);
            if slices.is_empty() {
                return None;
            }
            for slice in &slices {
                for &byte in slice.iter() {
                    if byte == 0 {
                        return Some(string);
                    }
                    string.push(byte as char);
                }
            }
            pos += max_read;
        }
    }
    /// Check if the address range is mapped in any map area
    pub fn is_mapped(&self, start_va: VirtAddr, end_va: VirtAddr) -> bool {
        let start_vpn: VirtPageNum = start_va.floor();
        let end_vpn: VirtPageNum = end_va.ceil();
        self.areas.iter().any(|area| {
            area.vpn_range.get_start() < end_vpn && area.vpn_range.get_end() > start_vpn
        })
    }
    /// Find an area without mapped
    pub fn find_free_area(&self, len: usize) -> usize {
        let mut current_start = 0x4000_0000;
        while current_start < 0x8000_0000 {
            let end = current_start + len;
            if !self.is_mapped(current_start.into(), end.into()) {
                return current_start;
            }
            current_start += PAGE_SIZE;
        }
        0
    }
    /// Insert
    pub fn insert_framed_area(&mut self, start_va: VirtAddr, end_va: VirtAddr, permission: MapPermission) {
        self.push(
            MapArea::new(start_va, end_va, MapType::Framed, permission),
            None,
            0,
        );
    }
    /// Insert shared area (MAP_SHARED)
    pub fn insert_shared_area(&mut self, start_va: VirtAddr, end_va: VirtAddr, permission: MapPermission) {
        self.push(
            MapArea::new(start_va, end_va, MapType::Shared, permission),
