#[cfg(target_arch = "riscv64")]
bitflags! {
    /// Sv39 page table entry flags (RISC-V).
    pub struct PTEFlags: u8 {
        /// Valid
        const V = 1 << 0;
        /// Readable
        const R = 1 << 1;
        /// Writable
        const W = 1 << 2;
        /// Executable
        const X = 1 << 3;
        /// User-accessible
        const U = 1 << 4;
        /// Global (ignore ASID in TLB match)
        const G = 1 << 5;
        /// Accessed (hardware sets on read/write/fetch)
        const A = 1 << 6;
        /// Dirty (hardware sets on write)
        const D = 1 << 7;
    }
}

#[cfg(target_arch = "loongarch64")]
#[cfg(target_arch = "loongarch64")]
bitflags! {
    /// LoongArch64 page table entry flags.
    pub struct PTEFlags: usize {
        /// Valid
        const V = 1 << 0;
        /// Dirty (hardware sets on write; also used as TLB write permission)
        const D = 1 << 1;
        /// PLV low bit (user-mode access when PLV=3)
        const PLVL = 1 << 2;
        /// PLV high bit (user-mode access when PLV=3)
        const PLVH = 1 << 3;
        /// MAT low bit (memory access type, e.g. coherent cached)
        const MATL = 1 << 4;
        /// MAT high bit (memory access type)
        const MATH = 1 << 5;
        /// Global (ignore ASID in TLB match)
        const G = 1 << 6;
        /// Physical (entry valid for hardware walk)
        const P = 1 << 7;
        /// Writable (TLB write permission mirror)
        const W = 1 << 8;
        /// Not Readable (reading triggers load page fault)
        const NR = 1 << 61;
        /// No Execute (execution triggers fetch page fault)
        const NX = 1 << 62;
        /// RPLV (privilege-level restriction, high bit)
        const RPLV = 1 << 63;
    }
}

#[cfg(target_arch = "loongarch64")]
/// Coherent Cached MAT encoding = 1 at bits [5:4] (`_CACHE_CC` = `1 << 4` = MATL).
const LA_PTE_MAT_CC: PTEFlags = PTEFlags::MATL;

#[cfg(target_arch = "loongarch64")]
/// Directory (non-leaf) PTE flags for hardware `lddir` / TLB refill.
///
/// Includes coherent cached MAT and user PLV (`PLVL|PLVH`) so hardware walk
/// accepts directory entries (Linux `_PAGE_TABLE` ≈ `P | V | _CACHE_CC | _PAGE_PLV`).
const LA_DIR_PTE_FLAGS: PTEFlags = PTEFlags::P
    .union(PTEFlags::V)
    .union(LA_PTE_MAT_CC);

