/// 支持各种文件的 open_file
pub fn open_file(path: &str, flags: u32, create_mode: Option<u32>, has_create: Option<bool>) -> Result<Arc<dyn File + Send + Sync>, isize> {
    type DynFileArc = Arc<dyn File + Send + Sync>;
    if path.starts_with("/dev") {
        open_dev(path).ok_or(-1)
    } else if path.starts_with("/proc") {
        open_proc(path).ok_or(-1)
    } else if path == "/etc/protocols" || path == "/etc/protocols/" {
        Ok(Arc::new(ProcFile::new(String::from("/etc/protocols"))) as DynFileArc)
    } else if path == "/etc/passwd" || path == "/etc/passwd/" {
        debug!("[open_file] /etc/passwd opened, pid={}", current_process().getpid());
        Ok(Arc::new(ProcFile::new(String::from("/etc/passwd"))) as DynFileArc)
    } else if path == "/etc/group" || path == "/etc/group/" {
        debug!("[open_file] /etc/group opened, pid={}", current_process().getpid());
        Ok(Arc::new(ProcFile::new(String::from("/etc/group"))) as DynFileArc)
    } else if has_create == Some(true) {
        open_or_create(&path, flags, create_mode.unwrap(), true)
    } else {
        let inode = open_inode(path, flags, true)?;
        if inode.get_file_type() == InodeTypes::EXT4_INODE_MODE_DIRECTORY
            && (flags & 0b11) != 0 {
            return Err(-EISDIR);
        }
        Ok(inode as DynFileArc)
    }
}

