/// 注册已打开的 inode，返回 generation
pub fn register_opened_inode(ino: u32, path: &str) -> u32 {
    let gen = (get_time_us() & 0xFFFF_FFFF) as u32;
    let mut registry = INODE_REGISTRY.exclusive_access();
    registry.insert(ino, InodeRegistryEntry {
        generation: gen,
        path: String::from(path),
    });
    gen
}

/// 按 inode + generation 查找路径，generation 不匹配返回 None
pub fn lookup_inode_path(ino: u32, generation: u32) -> Option<String> {
    let registry = INODE_REGISTRY.exclusive_access();
    registry.get(&ino).and_then(|e| {
        if e.generation == generation { Some(e.path.clone()) } else { None }
    })
}

