/// 生成 /proc/meminfo 内容
fn generate_meminfo() -> Vec<u8> {
    let stats = frame_stats();
    let page_size_kb = 4;
    let total_kb = stats.total_pages * page_size_kb;
    let free_kb = stats.free_pages * page_size_kb;
    let used_kb = total_kb - free_kb;
    let mut content = String::new();
    content.push_str(&format!("MemTotal:      {:8} kB\n", total_kb));
    content.push_str(&format!("MemFree:       {:8} kB\n", free_kb));
    content.push_str(&format!("MemAvailable:  {:8} kB\n", free_kb));
    content.push_str(&format!("Buffers:       {:8} kB\n", 0u32));
    content.push_str(&format!("Cached:        {:8} kB\n", 0u32));
    content.push_str(&format!("SwapCached:    {:8} kB\n", 0u32));
    content.push_str(&format!("Active:        {:8} kB\n", used_kb / 2));
    content.push_str(&format!("Inactive:      {:8} kB\n", used_kb / 2));
    content.push_str(&format!("SwapTotal:     {:8} kB\n", 0u32));
    content.push_str(&format!("SwapFree:      {:8} kB\n", 0u32));
    content.push_str(&format!("Dirty:         {:8} kB\n", 0u32));
    content.push_str(&format!("Writeback:     {:8} kB\n", 0u32));
    content.push_str(&format!("Mapped:        {:8} kB\n", used_kb / 4));
    content.push_str(&format!("Slab:          {:8} kB\n", 0u32));
    content.into_bytes()
}

/// 生成 /proc/mounts 内容
