use core::sync::atomic::{AtomicBool, Ordering};
use alloc::sync::{Arc, Weak};

use crate::task::suspend_current_and_run_next;

/// IPC pipe
pub struct Pipe {
    readable: bool,
    writable: bool,
    is_nonblock: AtomicBool,
    buffer: Arc<UPSafeCell<PipeRingBuffer>>,
}

impl Pipe {
    /// create readable pipe
    pub fn read_end_with_buffer(buffer: Arc<UPSafeCell<PipeRingBuffer>>) -> Self {
        Self {
            readable: true,
            writable: false,
            is_nonblock: AtomicBool::new(false),
            buffer,
        }
    }
    /// create writable pipe
    pub fn write_end_with_buffer(buffer: Arc<UPSafeCell<PipeRingBuffer>>) -> Self {
        Self {
            readable: false,
            writable: true,
            is_nonblock: AtomicBool::new(false),
            buffer,
        }
    }
    /// have sth to read
    pub fn have_sth_to_read(&self) -> bool {
        if !self.readable {
            return false;
        }
        let ring_buffer = self.buffer.exclusive_access();
        // error!("{} {}", ring_buffer.available_read() > 0, ring_buffer.all_write_ends_closed());
        ring_buffer.available_read() > 0 || ring_buffer.all_write_ends_closed()
    }
    /// have sth to write
    pub fn have_sth_to_write(&self) -> bool {
        if !self.writable {
            return false;
        }
        let ring_buffer = self.buffer.exclusive_access();
        ring_buffer.available_write() > 0
    }
    /// set block or not
    pub fn set_is_nonblock(&self, is_nonblock: bool) {
        self.is_nonblock.store(is_nonblock, Ordering::Relaxed);
    }
}

const RING_BUFFER_SIZE: usize = 4096;

#[derive(Copy, Clone, PartialEq)]
enum RingBufferStatus {
    Full,
    Empty,
    Normal,
}

pub struct PipeRingBuffer {
    arr: [u8; RING_BUFFER_SIZE],
    head: usize,
    tail: usize,
    status: RingBufferStatus,
    write_end: Option<Weak<Pipe>>,
}

impl PipeRingBuffer {
    pub fn new() -> Self {
        Self {
            arr: [0; RING_BUFFER_SIZE],
            head: 0,
            tail: 0,
            status: RingBufferStatus::Empty,
            write_end: None,
        }
    }
    pub fn set_write_end(&mut self, write_end: &Arc<Pipe>) {
        self.write_end = Some(Arc::downgrade(write_end));
    }
    pub fn write_byte(&mut self, byte: u8) {
        self.status = RingBufferStatus::Normal;
        self.arr[self.tail] = byte;
        self.tail = (self.tail + 1) % RING_BUFFER_SIZE;
        if self.tail == self.head {
            self.status = RingBufferStatus::Full;
        }
    }
    pub fn read_byte(&mut self) -> u8 {
        self.status = RingBufferStatus::Normal;
        let c = self.arr[self.head];
        self.head = (self.head + 1) % RING_BUFFER_SIZE;
        if self.head == self.tail {
            self.status = RingBufferStatus::Empty;
        }
        c
    }
    pub fn available_read(&self) -> usize {
        if self.status == RingBufferStatus::Empty {
            0
        } else if self.tail > self.head {
            self.tail - self.head
        } else {
            self.tail + RING_BUFFER_SIZE - self.head
        }
    }
    pub fn available_write(&self) -> usize {
        if self.status == RingBufferStatus::Full {
            0
        } else {
            RING_BUFFER_SIZE - self.available_read()
        }
    }
    pub fn all_write_ends_closed(&self) -> bool {
        self.write_end.as_ref().unwrap().upgrade().is_none()
    }
}

/// Return (read_end, write_end)
pub fn make_pipe() -> (Arc<Pipe>, Arc<Pipe>) {
    trace!("kernel: make_pipe");
    let buffer = Arc::new(unsafe { UPSafeCell::new(PipeRingBuffer::new()) });
    let read_end = Arc::new(Pipe::read_end_with_buffer(buffer.clone()));
    let write_end = Arc::new(Pipe::write_end_with_buffer(buffer.clone()));
    buffer.exclusive_access().set_write_end(&write_end);
    (read_end, write_end)
}

impl File for Pipe {
    fn readable(&self) -> bool {
        self.readable
    }
    fn writable(&self) -> bool {
        self.writable
    }
    fn read(&self, buf: UserBuffer) -> usize {
        trace!("kernel: Pipe::read");
        assert!(self.readable());
        let want_to_read = buf.len();
        let mut buf_iter = buf.into_iter();
        let mut already_read = 0usize;
        loop {
            let mut ring_buffer = self.buffer.exclusive_access();
            let loop_read = ring_buffer.available_read();
            if loop_read == 0 {
                if ring_buffer.all_write_ends_closed() || already_read > 0 {
                    return already_read;
                }
                let is_nonblock = self.is_nonblock.load(Ordering::Relaxed);
                if is_nonblock {
                    return 0xfffffffffffffff5;
                }
                drop(ring_buffer);
                suspend_current_and_run_next();
                if current_task().unwrap().has_pending_signals() {
                    return 0xfffffffffffffffc;
                }
                continue;
            }
            for _ in 0..loop_read {
                if let Some(byte_ref) = buf_iter.next() {
                    unsafe {
                        *byte_ref = ring_buffer.read_byte();
                    }
                    already_read += 1;
                    if already_read == want_to_read {
                        return want_to_read;
                    }
                } else {
                    return already_read;
                }
            }
        }
    }
    fn write(&self, buf: UserBuffer) -> usize {
        // 写里可能也要判断阻塞什么的, 暂时先不实现
        trace!("kernel: Pipe::write");
        assert!(self.writable());
        let want_to_write = buf.len();
        let mut buf_iter = buf.into_iter();
        let mut already_write = 0usize;
        loop {
            let mut ring_buffer = self.buffer.exclusive_access();
            let loop_write = ring_buffer.available_write();
            if loop_write == 0 {
                drop(ring_buffer);
                suspend_current_and_run_next();
                continue;
            }
            // write at most loop_write bytes
            for _ in 0..loop_write {
                if let Some(byte_ref) = buf_iter.next() {
                    ring_buffer.write_byte(unsafe { *byte_ref });
                    already_write += 1;
                    if already_write == want_to_write {
                        return want_to_write;
                    }
                } else {
                    return already_write;
                }
            }
        }
    }
    fn write_any(&self, buf: &[u8]) -> usize { buf.len() }
    fn as_any(&self) -> &dyn core::any::Any {
        self
    }
}

//! eventfd 实现 —— 线程间通知用的计数器

use super::File;
use crate::mm::UserBuffer;
use crate::sync::UPSafeCell;

/// eventfd：64 位计数器，read 读取并清零，write 累加
pub struct EventFd {
    count: UPSafeCell<u64>,
}

impl EventFd {
    /// 创建 eventfd，初始值 initval
    pub fn new(initval: u64) -> Self {
        Self { count: unsafe { UPSafeCell::new(initval) } }
    }
}

impl File for EventFd {
    fn readable(&self) -> bool { true }
    fn writable(&self) -> bool { true }
    fn read(&self, mut buf: UserBuffer) -> usize {
        let count = self.count.exclusive_access();
        if *count == 0 {
            return 0;
        }
        let val_bytes = count.to_ne_bytes();
        drop(count);
        let mut copied = 0;
        for slice in buf.buffers.iter_mut() {
            let to_copy = core::cmp::min(slice.len(), 8 - copied);
            if to_copy == 0 { break; }
            slice[..to_copy].copy_from_slice(&val_bytes[copied..copied + to_copy]);
            copied += to_copy;
        }
        if copied >= 8 {
            *self.count.exclusive_access() = 0;
        }
        copied
    }
    fn write(&self, buf: UserBuffer) -> usize {
        let mut total: u64 = 0;
        for slice in buf.buffers.iter() {
            let mut val_bytes = [0u8; 8];
            let to_copy = core::cmp::min(slice.len(), 8);
            val_bytes[..to_copy].copy_from_slice(&slice[..to_copy]);
            total = total.wrapping_add(u64::from_ne_bytes(val_bytes));
        }
        *self.count.exclusive_access() += total;
        buf.len()
    }
    fn write_any(&self, buf: &[u8]) -> usize { buf.len() }
    fn as_any(&self) -> &dyn core::any::Any { self }
}

//! POSIX 消息队列（mqueue）文件系统实现

use super::File;
use crate::mm::UserBuffer;
use crate::sync::UPSafeCell;
use crate::task::suspend_current_and_run_next;
use crate::syscall::errno::*;
use alloc::collections::BTreeMap;
use alloc::collections::VecDeque;
use alloc::string::String;
use alloc::sync::Arc;
use alloc::vec;
use alloc::vec::Vec;
