/// mq_attr 结构（用户态）
#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub struct MqAttr {
    /// 队列标志（O_NONBLOCK）
    pub mq_flags: i64,
    /// 最大消息数
    pub mq_maxmsg: i64,
    /// 最大消息大小
    pub mq_msgsize: i64,
    /// 当前消息数
    pub mq_curmsgs: i64,
    /// 保留字段
    pub _reserved: [i64; 4],
}

impl Default for MqAttr {
    fn default() -> Self {
        Self {
            mq_flags: 0,
            mq_maxmsg: 10,
            mq_msgsize: 8192,
            mq_curmsgs: 0,
            _reserved: [0; 4],
        }
    }
}

/// sigevent 结构（简化版）
#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub struct Sigevent {
    /// 通知值
    pub sigev_value: usize,
    /// 信号编号
    pub sigev_signo: i32,
    /// 通知方式
    pub sigev_notify: i32,
    /// 通知函数指针
    pub sigev_notify_function: usize,
    /// 通知线程属性
    pub sigev_notify_attributes: usize,
    /// 通知线程 ID
    pub sigev_notify_thread_id: usize,
}

/// 消息队列内部数据
pub struct MqueueInner {
    /// 队列名
    pub name: String,
    /// 队列属性
    pub attr: MqAttr,
    /// 消息列表（数据, 优先级）
    pub messages: VecDeque<(Vec<u8>, u32)>,
    /// 非阻塞模式
    pub nonblock: bool,
    /// 已标记删除
    pub unlinked: bool,
}

/// POSIX 消息队列文件对象
pub struct Mqueue {
    /// 内部可共享数据
    pub inner: Arc<UPSafeCell<MqueueInner>>,
}

lazy_static! {
    static ref MQUEUE_REGISTRY: UPSafeCell<BTreeMap<String, Arc<UPSafeCell<MqueueInner>>>> =
        unsafe { UPSafeCell::new(BTreeMap::new()) };
}

impl Mqueue {
    /// 创建或打开消息队列
    pub fn new(name: &str, flags: i32, _mode: u32, attr: Option<&MqAttr>) -> Result<Self, isize> {
        const O_CREAT: i32 = 0o100;
        const O_EXCL: i32 = 0o200;
        const O_NONBLOCK: i32 = 0x800;
        let create = flags & O_CREAT != 0;
        let excl = flags & O_EXCL != 0;
        let nonblock = flags & O_NONBLOCK != 0;

        let mut registry = MQUEUE_REGISTRY.exclusive_access();
        let default_attr = MqAttr::default();
        let mq_attr = attr.unwrap_or(&default_attr);

        if create {
            if registry.contains_key(name) {
                if excl {
                    return Err(-17); // EEXIST
                }
                let inner = registry.get(name).unwrap().clone();
                inner.exclusive_access().nonblock = nonblock;
                return Ok(Mqueue { inner });
            }
            if mq_attr.mq_maxmsg <= 0 || mq_attr.mq_msgsize <= 0 {
                return Err(-22); // EINVAL
            }
            let inner = Arc::new(unsafe {
                UPSafeCell::new(MqueueInner {
                    name: String::from(name),
                    attr: *mq_attr,
                    messages: VecDeque::new(),
                    nonblock,
                    unlinked: false,
                })
            });
            registry.insert(String::from(name), inner.clone());
            Ok(Mqueue { inner })
        } else {
            match registry.get(name) {
                Some(inner) => {
                    inner.exclusive_access().nonblock = nonblock;
                    Ok(Mqueue { inner: inner.clone() })
                }
                None => Err(-2), // ENOENT
            }
        }
    }

    /// 删除消息队列
    pub fn unlink(name: &str) -> isize {
        let mut registry = MQUEUE_REGISTRY.exclusive_access();
        if registry.contains_key(name) {
            registry.get(name).unwrap().exclusive_access().unlinked = true;
        }
        registry.remove(name);
        0
    }

    /// 发送消息
    pub fn send(&self, msg: &[u8], prio: u32) -> isize {
        loop {
            let mut inner = self.inner.exclusive_access();
            if inner.unlinked {
                return -EINVAL;
            }
            if inner.messages.len() < inner.attr.mq_maxmsg as usize {
                inner.messages.push_back((msg.to_vec(), prio));
                let cur = inner.messages.len() as i64;
                inner.attr.mq_curmsgs = cur;
                return 0;
            }
            if inner.nonblock {
                return -EAGAIN;
            }
            drop(inner);
            suspend_current_and_run_next();
        }
    }

    /// 接收消息
    pub fn receive(&self, buf: &mut [u8]) -> isize {
        loop {
            let mut inner = self.inner.exclusive_access();
            if !inner.messages.is_empty() {
                let (data, _prio) = inner.messages.pop_front().unwrap();
                let copy_len = core::cmp::min(data.len(), buf.len());
                buf[..copy_len].copy_from_slice(&data[..copy_len]);
                let cur = inner.messages.len() as i64;
                inner.attr.mq_curmsgs = cur;
                return copy_len as isize;
            }
            if inner.unlinked {
                return -EINVAL;
            }
            if inner.nonblock {
                return -EAGAIN;
            }
            drop(inner);
            suspend_current_and_run_next();
        }
    }
}

impl File for Mqueue {
    fn readable(&self) -> bool { true }
    fn writable(&self) -> bool { true }
    fn read(&self, mut buf: UserBuffer) -> usize {
        let total = buf.buffers.iter().map(|s| s.len()).sum();
        let mut tmp = vec![0u8; total];
        let result = self.receive(&mut tmp);
        if result <= 0 { return 0; }
        let len = result as usize;
        let mut off = 0;
        for slice in buf.buffers.iter_mut() {
            let n = core::cmp::min(slice.len(), len - off);
            slice[..n].copy_from_slice(&tmp[off..off + n]);
            off += n;
            if off >= len { break; }
        }
        len
    }
    fn write(&self, buf: UserBuffer) -> usize {
        let mut tmp = vec![];
        for slice in buf.buffers.iter() { tmp.extend(slice.iter().copied()); }
        let len = tmp.len();
        match self.send(&tmp, 0) { 0 => len, _ => 0 }
    }
    fn write_any(&self, buf: &[u8]) -> usize { buf.len() }
    fn as_any(&self) -> &dyn core::any::Any { self }
}

use crate::mm::UserBuffer;
use crate::sync::UPSafeCell;
