/// fanotify 事件元数据结构（与 Linux struct fanotify_event_metadata 兼容）
#[repr(C)]
#[derive(Clone, Debug)]
pub struct FanotifyEventMeta {
    event_len: u32,
    vers: u8,
    reserved: u8,
    metadata_len: u16,
    mask: u64,
    fd: i32,
    pid: i32,
}

const FAN_METADATA_VERSION: u8 = 3;

impl FanotifyEventMeta {
    fn new(mask: u64, pid: i32) -> Self {
        Self {
            event_len: core::mem::size_of::<Self>() as u32,
            vers: FAN_METADATA_VERSION,
            reserved: 0,
            metadata_len: core::mem::size_of::<Self>() as u16,
            mask,
            fd: -1, // 不提供事件关联的 fd
            pid,
        }
    }
}

///
pub struct FanotifyGroup {
    ///
    pub events: UPSafeCell<Vec<FanotifyEventMeta>>,
    ///
    pub marks: UPSafeCell<Vec<(String, u64)>>,
}

///
pub struct FanotifyFile {
    ///
    pub group: Arc<FanotifyGroup>,
}

impl FanotifyFile {
    ///
    pub fn new(group: Arc<FanotifyGroup>) -> Self {
        Self { group }
    }
}

lazy_static! {
    /// 全局只记录【弱引用】，不持有所有权。
    pub static ref FANOTIFY_GROUPS: UPSafeCell<Vec<Weak<FanotifyGroup>>> = unsafe {
        UPSafeCell::new(Vec::new())
    };
}

/// 当文件被操作时，向所有监听该路径的 fanotify 实例推送事件
pub fn fanotify_push_event(path: &str, event_mask: u64) {
    const FAN_EVENT_ON_CHILD: u64 = 0x08000000;
    let pid = current_process().getpid() as i32;
    let mut groups = FANOTIFY_GROUPS.exclusive_access();
    groups.retain(|weak_group| {
        // 尝试将弱引用提升为强引用 Arc
        if let Some(group) = weak_group.upgrade() {
            // 提升成功，说明这个监听实例还活着，开始检查它的 marks
            let marks = group.marks.exclusive_access();
            let mut events = group.events.exclusive_access();
            for (marked_path, mark_mask) in marks.iter() {
                let is_exact = path == marked_path.as_str();
                let dir_prefix = format!("{}/", marked_path.trim_end_matches('/'));
                let is_child = !is_exact && path.starts_with(&dir_prefix);
                // FAN_EVENT_ON_CHILD 控制匹配子文件还是 mark 自身
                let path_matches = if mark_mask & FAN_EVENT_ON_CHILD != 0 {
                    is_child
                } else {
                    is_exact
                };
                // 如果路径匹配且事件类型正确
                if path_matches && (mark_mask & event_mask != 0) {
                    let ev = FanotifyEventMeta::new(event_mask, pid);
                    // 直接精准塞入该实例私有的事件队列中！
                    events.push(ev);
                }
            }
            true // 实例还活着，继续保留在全局通知链中
        } else {
            false // 提升失败！说明对应的进程/文件已经被 close 销毁了，直接从全局链表中剔除！
        }
    });
}

impl File for FanotifyFile {
    fn readable(&self) -> bool {
        true
    }
    fn writable(&self) -> bool {
        true
    }
    fn read(&self, mut buf: UserBuffer) -> usize {
        let mut events = self.group.events.exclusive_access();
        if events.is_empty() {
            return 0;
        }
        let meta_size = core::mem::size_of::<FanotifyEventMeta>();
        let max_count = buf.len() / meta_size;
        let count = events.len().min(max_count);
        if count == 0 {
            return 0;
        }
        let drained: Vec<FanotifyEventMeta> = events.drain(..count).collect();
        drop(events);
        let total_bytes = count * meta_size;
        let src = unsafe {
            core::slice::from_raw_parts(
                drained.as_ptr() as *const u8,
                total_bytes,
            )
        };
