    fn calculate_tcp_checksum(&self, header: &TcpHeader, data: &[u8]) -> u16 {
        let mut sum = 0u32;
        // 包含：源 IP (4字节), 目的 IP (4字节), 保留 (1字节=0), 协议号 (1字节=6), TCP总长度 (2字节)
        let src_bytes = 0u32.to_be_bytes();
        let dst_bytes = 0u32.to_be_bytes();
        for chunk in src_bytes.chunks(2) {
            sum += u16::from_be_bytes([chunk[0], chunk[1]]) as u32;
        }
        for chunk in dst_bytes.chunks(2) {
            sum += u16::from_be_bytes([chunk[0], chunk[1]]) as u32;
        }
        sum += 6u32;
        sum += (core::mem::size_of::<TcpHeader>() + data.len()) as u32;
        let header_bytes = unsafe {
            core::slice::from_raw_parts(
                header as *const TcpHeader as *const u16,
                core::mem::size_of::<TcpHeader>() / 2
            )
        };
        for &word in header_bytes {
            sum += u16::from_be(word) as u32;
        }
        while sum >> 16 != 0 {
            sum = (sum & 0xffff) + (sum >> 16);
        }
        !(sum as u16)
    }
