/// shmget 系统调用：获取共享内存段
///
/// 参数：
/// - key: 共享内存键值（0 = IPC_PRIVATE 即私有匿名段）
/// - size: 段大小（字节）
/// - shmflg: 标志位（IPC_CREAT=0o1000, IPC_EXCL=0o2000, 低 9 位为权限 mode）
pub fn sys_shmget(key: usize, size: usize, shmflg: u32) -> isize {
    trace!("sys_shmget: process {} shmget key = {} size ={} shmflg = {}", current_process().getpid(), key, size, shmflg);
    const IPC_CREAT: u32 = 0o1000;
    const IPC_EXCL: u32 = 0o2000;
    if size == 0 {
        return -EINVAL;
    }
    let mut manager = SHM_MANAGER.exclusive_access();
    // IPC_PRIVATE：总是创建新段
    if key == 0 {
        return manager.create(key, size, shmflg);
    }
    // 按 key 查找已存在的段
    if let Some(idx) = manager.find_by_key(key) {
        if (shmflg & IPC_CREAT) != 0 && (shmflg & IPC_EXCL) != 0 {
            return -EEXIST;
        }
        // 允许重新获取时 size 更小或相等
        let seg = manager.segments[idx].as_ref().unwrap();
        if size > seg.size {
            return -EINVAL;
        }
        // 检查权限：请求者需要对段有访问权限
        let mode = shmflg & 0o777;
        let seg_mode = seg.mode as u32;
        if (mode & !seg_mode) != 0 {
            return -EACCES;
        }
        return seg.id as isize;
    }
    // 不存在且没有 IPC_CREAT
    if (shmflg & IPC_CREAT) == 0 {
        return -ENOENT;
    }
    manager.create(key, size, shmflg)
}

/// shmat 系统调用：将共享内存段映射到进程地址空间
///
/// 参数：
/// - shmid: 共享内存段 ID
/// - shmaddr: 建议映射地址（0 表示由内核选择）
/// - shmflg: 标志位（SHM_RDONLY=0o10000, SHM_RND=0o20000, SHM_REMAP=0o40000）
pub fn sys_shmat(shmid: usize, shmaddr: usize, shmflg: u32) -> isize {
    trace!("sys_shmat: process {} shmat shmid = {}, shmaddr = {}, shmflg = {}", current_process().getpid(), shmid, shmaddr, shmflg);
    const SHM_RDONLY: u32 = 0o10000;
    const SHM_RND: u32 = 0o20000;
    let manager = SHM_MANAGER.exclusive_access();
    let seg_idx = match manager.find_by_id(shmid) {
        Some(i) => i,
        None => return -EINVAL,
    };
    let (frame_count, deleted) = {
        let seg = manager.segments[seg_idx].as_ref().unwrap();
        (seg.frames.len(), seg.deleted)
    };
    if deleted {
        return -EIDRM;
    }
    if frame_count == 0 {
        return -ENOMEM;
    }
    // 克隆 FrameTracker 引用（Arc 引用计数 +1）
    let frames: Vec<Arc<FrameTracker>> = {
        let seg = manager.segments[seg_idx].as_ref().unwrap();
        seg.frames.iter().cloned().collect()
    };
    drop(manager);
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    let map_va = if shmaddr == 0 {
        inner.memory_set.find_free_area(frame_count * PAGE_SIZE)
    } else {
        if (shmflg & SHM_RND) != 0 {
            shmaddr & !(PAGE_SIZE - 1)
        } else {
            if shmaddr % PAGE_SIZE != 0 {
                return -EINVAL;
            }
            shmaddr
        }
    };
    if map_va == 0 {
        return -ENOMEM;
    }
    let start_va = VirtAddr::from(map_va);
    let end_va = VirtAddr::from(map_va + frame_count * PAGE_SIZE);
    let perm = if (shmflg & SHM_RDONLY) != 0 {
        MapPermission::R | MapPermission::U
    } else {
        MapPermission::R | MapPermission::W | MapPermission::U
    };
    inner.memory_set.map_existing_frames(start_va, end_va, perm, frames);
    drop(inner);
    // 更新 attach 计数
    let mut manager = SHM_MANAGER.exclusive_access();
    if let Some(seg) = manager.segments[seg_idx].as_mut() {
        seg.nattch += 1;
        seg.attach_addr = map_va;
        seg.lpid = current_process().getpid();
        seg.atime = get_time() as i64;
    }
    map_va as isize
}

/// shmctl 系统调用：控制共享内存段
///
/// 参数：
/// - shmid: 共享内存段 ID
/// - cmd: 命令（IPC_RMID=0, IPC_SET=1, IPC_STAT=2）
