pub fn sys_shmctl(shmid: usize, cmd: u32, buf: *mut u8) -> isize {
    trace!("sys_shmctl: process {} shmid = {}, cmd = {}", current_process().getpid(), shmid, cmd);
    const IPC_RMID: u32 = 0;
    const IPC_SET: u32 = 1;
    const IPC_STAT: u32 = 2;
    const SHM_LOCK: u32 = 11;
    const SHM_UNLOCK: u32 = 12;
    if (cmd == IPC_STAT || cmd == IPC_SET) && !buf.is_null() {
        if current_process().inner_exclusive_access().memory_set.translated_byte_buffer(buf as *const u8, 1, 1).is_empty() || (buf as isize) < 0 { 
            return -EFAULT;
        }
    }
    let mut manager = SHM_MANAGER.exclusive_access();
    let seg_idx = match manager.find_by_id(shmid) {
        Some(i) => i,
        None => return -EINVAL,
    };
    match cmd {
        IPC_RMID => {
            let seg = manager.segments[seg_idx].as_mut().unwrap();
            // 只允许 owner 或 root (uid=0) 删除
            let cred = current_process().inner_exclusive_access().cred.clone();
            let cur_uid = cred.euid;
