            if seg.nattch == 0 {
                manager.segments[seg_idx] = None;
            }
            0
        }
        IPC_STAT => {
            if buf.is_null() {
                return -EFAULT;
            }
            let token = current_user_token();
            let seg = manager.segments[seg_idx].as_ref().unwrap();
            let ds = ShmIdDs {
                perm_key: seg.key as i32,
                perm_uid: seg.uid,
                perm_gid: seg.gid,
                perm_cuid: seg.cuid,
                perm_cgid: seg.cgid,
                perm_mode: seg.mode as u32,
                perm_seq: 0,
                perm_pad1: 0,
                perm_unused1: 0,
                perm_unused2: 0,
                shm_segsz: seg.size as u64,
                shm_atime: seg.atime,
                shm_dtime: seg.dtime,
                shm_ctime: seg.ctime,
                shm_cpid: seg.cpid as i32,
                shm_lpid: seg.lpid as i32,
                shm_nattch: seg.nattch as u64,
                unused0: 0,
                unused1: 0,
            };
            *translated_refmut(token, buf as *mut ShmIdDs) = ds;
            0
        }
        IPC_SET => {
            if buf.is_null() {
                return -EFAULT;
            }
            let token = current_user_token();
            let cred = current_process().inner_exclusive_access().cred.clone();
            let cur_uid = cred.euid;
            let ds = translated_ref(token, buf as *const ShmIdDs);
            let seg = manager.segments[seg_idx].as_mut().unwrap();
            if cur_uid != seg.uid && cur_uid != seg.cuid && !cred.capable(CAP_IPC_OWNER) {
                return -EPERM;
            }
            seg.uid = ds.perm_uid;
            seg.gid = ds.perm_gid;
            seg.mode = (ds.perm_mode & 0o777) as u16;
            seg.ctime = get_time() as i64;
            0
        }
        SHM_LOCK | SHM_UNLOCK => {
            let euid = current_process().inner_exclusive_access().cred.euid;
            if euid != 0 {
                -EPERM
            } else {
                -ENOSYS
            }
        }
        _ => -EINVAL,
    }
}

