/// 按端口向 DGRAM socket 投递数据（用于 sendto 情况 B）
pub fn try_deliver_to_dgram(port: u16, sock_type: usize, data: &[u8], src_port: u16) {
    let registry = SOCKET_REGISTRY.exclusive_access();
    if let Some(target) = registry.get(&(port, sock_type)) {
        let mut target_inner = target.exclusive_access();
        if target_inner.domain == 10 && target_inner.protocol == 58 {
            let icmp_type = data[0];
            if icmp6_filter_block(&target_inner, icmp_type) {
                trace!("[NET] Drop ICMPv6 packet type {} by filter", icmp_type);
                return;
            }
        }
        target_inner.rx_buffer.extend(data.iter().copied());
        target_inner.last_src_port = src_port;
    }
}

/// 检查当前 Socket 是否应该丢弃该 ICMPv6 报文
pub fn icmp6_filter_block(sock_inner: &SocketInner, icmp_type: u8) -> bool {
    let word_idx = (icmp_type >> 5) as usize;
    let bit_idx = (icmp_type & 31) as usize;
    (sock_inner.icmp6_filter[word_idx] & (1 << bit_idx)) != 0
}

/// 连接到一个监听中的 socket（按端口查找）
pub fn socket_connect(client: &Socket, port: u16) -> isize {
    let local_port = client.local_port();
    let sock_type = client.inner.exclusive_access().sock_type;
    if local_port == 0 {
        // 要为它隐式绑定一个临时端口
        let port_loader = 49152..65535;
        let mut ephemeral_port = 0;
        let registry = SOCKET_REGISTRY.exclusive_access();
        for p in port_loader {
            if !registry.contains_key(&(p, sock_type)) {
                ephemeral_port = p;
                break;
            }
        }
        drop(registry);
        client.inner.exclusive_access().local_port = ephemeral_port;
        SOCKET_REGISTRY.exclusive_access().insert((ephemeral_port, sock_type), client.inner.clone());
    }
    let registry = SOCKET_REGISTRY.exclusive_access();
    if let Some(server_inner) = registry.get(&(port, sock_type)) {
        if sock_type == 1 {
            let mut server = server_inner.exclusive_access();
            if server.state != SocketState::Listening {
                return -ECONNREFUSED;
            }
            // 为服务端独立创建一个连接成功的 SocketInner
            let server_connected_inner = Arc::new(unsafe {
                UPSafeCell::new(SocketInner {
                    state: SocketState::Connected,
                    domain: server.domain,
                    sock_type: server.sock_type,
                    is_block: server.is_block,
                    protocol: server.protocol,
                    local_port: port,
                    last_src_port: port,
                    created_for_connect: true,
                    pending: VecDeque::new(),
                    multicast_groups: Vec::new(),
                    rx_buffer: VecDeque::new(),
                    peer: Some(Arc::downgrade(&client.inner)),
                    last_change_time: get_time_us(),
                    ipv6_checksum_offset: None,
                    icmp6_filter: [0; 8],
                    ipv6_opts: Ipv6AncillaryOptions::default(),
                })
            });

            // 配置客户端的状态与对端指针
            let mut client_inner = client.inner.exclusive_access();
            client_inner.state = SocketState::Connected;
            client_inner.peer = Some(Arc::downgrade(&server_connected_inner));
            drop(client_inner);
            // 将服务端的连接半体放入监听队列中，供 accept 弹出
            server.pending.push_back(server_connected_inner);
        }
        if sock_type == 2 {
            let mut client_inner = client.inner.exclusive_access();
            client_inner.state = SocketState::Connected;
            client_inner.peer = Some(Arc::downgrade(&server_inner));
            drop(client_inner);
        }
        0
    } else {
        // 只是探路
        if sock_type == 2 {
            return 0;
        }
        -ECONNREFUSED
    }
}

