use super::{PhysAddr, PhysPageNum};
use crate::sync::UPSafeCell;
use alloc::vec::Vec;
use core::fmt::{self, Debug, Formatter};
use lazy_static::*;

/// Bits per word in the bitmap.
const BITS: usize = core::mem::size_of::<usize>() * 8;

#[cfg(target_arch = "riscv64")]
use crate::config::MEMORY_END;
#[cfg(target_arch = "loongarch64")]
use crate::config::{
    dmw_to_phys, MEMORY_HIGH_END, MEMORY_LOW_END, MEMORY_LOW_START,
};

/// tracker for physical page frame allocation and deallocation
pub struct FrameTracker {
    /// physical page number
    pub ppn: PhysPageNum,
}

impl FrameTracker {
    /// Create a new FrameTracker
    pub fn new(ppn: PhysPageNum) -> Self {
        // page cleaning
        let bytes_array = ppn.get_bytes_array();
        for i in bytes_array {
            *i = 0;
        }
        Self { ppn }
    }
}

impl Debug for FrameTracker {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("FrameTracker:PPN={:#x}", self.ppn.0))
    }
}

impl Drop for FrameTracker {
    fn drop(&mut self) {
        frame_dealloc(self.ppn);
    }
}

trait FrameAllocator {
    fn new() -> Self;
    fn alloc(&mut self) -> Option<PhysPageNum>;
    fn dealloc(&mut self, ppn: PhysPageNum);
    fn free_pages(&self) -> usize;
    fn total_pages(&self) -> usize;
}

#[cfg(target_arch = "riscv64")]
pub struct StackFrameAllocator {
    current: usize,
    end: usize,
    recycled: Vec<usize>,
    total_alloc: usize,
    total_dealloc: usize,
    /// Bitmap for O(1) duplicate check on dealloc.
    /// Indexed by (ppn - base), covering [base, end).
    base: usize,
    bitmap: Vec<usize>,
}

#[cfg(target_arch = "riscv64")]
impl StackFrameAllocator {
    pub fn init(&mut self, l: PhysPageNum, r: PhysPageNum) {
        self.current = l.0;
        self.end = r.0;
        self.base = l.0;
        let pages = r.0 - l.0;
        let words = (pages + BITS - 1) / BITS;
        self.bitmap.resize(words, 0);
    }
    pub fn alloc_contiguous(&mut self, pages: usize) -> Option<Vec<PhysPageNum>> {
        if pages == 0 {
            return Some(Vec::new());
        }
        if self.current + pages <= self.end {
            let start = self.current;
            self.current += pages;
            self.total_alloc += pages;
            Some((0..pages).map(|i| PhysPageNum(start + i)).collect())
        } else {
            None
        }
    }
}

#[cfg(target_arch = "riscv64")]
impl FrameAllocator for StackFrameAllocator {
    fn new() -> Self {
        Self {
            current: 0,
            end: 0,
            recycled: Vec::new(),
            total_alloc: 0,
            total_dealloc: 0,
            base: 0,
            bitmap: Vec::new(),
        }
    }
    fn alloc(&mut self) -> Option<PhysPageNum> {
        let result = if let Some(ppn) = self.recycled.pop() {
            let idx = ppn - self.base;
            // Safety: bitmap bit must be 1 before we clear it

            self.bitmap[idx / BITS] &= !(1 << (idx % BITS));
            Some(ppn.into())
        } else if self.current == self.end {
            None
        } else {
            self.current += 1;
            Some((self.current - 1).into())
        };
        if result.is_some() {
            self.total_alloc += 1;
        }
        result
    }
    fn dealloc(&mut self, ppn: PhysPageNum) {
        let ppn = ppn.0;
        if ppn < self.base || ppn >= self.current {
            panic!("Frame ppn={:#x} has not been allocated!", ppn);
        }
        let idx = ppn - self.base;
        if (self.bitmap[idx / BITS] >> (idx % BITS)) & 1 != 0 {
            panic!("Frame ppn={:#x} has been deallocated!", ppn);
        }
        self.bitmap[idx / BITS] |= 1 << (idx % BITS);
        self.total_dealloc += 1;
        self.recycled.push(ppn);
    }
    fn free_pages(&self) -> usize {
        (self.end - self.current) + self.recycled.len()
    }
    fn total_pages(&self) -> usize {
        let used = self.total_alloc - self.total_dealloc;
        self.free_pages() + used
    }
}

#[cfg(target_arch = "riscv64")]
impl StackFrameAllocator {
    pub fn debug_state(&self) {
        trace!(
            "[frame_alloc] current={:#x}, end={:#x}, recycled_len={}",
            self.current,
            self.end,
            self.recycled.len()
        );
    }
}

/// LoongArch allocator: low RAM then high RAM, skipping the device hole.
#[cfg(target_arch = "loongarch64")]
pub struct LaFrameAllocator {
    low_start: usize,
    low_current: usize,
    low_end: usize,
    high_start: usize,
    high_current: usize,
    high_end: usize,
    /// Fixed pool size set at init: (low_end - low_start) + (high_end - high_start).
    total_pages: usize,
    recycled: Vec<usize>,
    total_alloc: usize,
    total_dealloc: usize,
    /// Bitmap for O(1) duplicate check on dealloc.
    /// Low range at offset [0, low_len), high range at offset [low_len, total_pages).
    bitmap: Vec<usize>,
}

#[cfg(target_arch = "loongarch64")]
impl LaFrameAllocator {
    pub fn init(
        &mut self,
        low_l: PhysPageNum,
        low_r: PhysPageNum,
        high_l: PhysPageNum,
        high_r: PhysPageNum,
    ) {
        self.low_start = low_l.0;
        self.low_current = low_l.0;
        self.low_end = low_r.0;
        self.high_start = high_l.0;
        self.high_current = high_l.0;
        self.high_end = high_r.0;
        self.total_pages = (low_r.0 - low_l.0) + (high_r.0 - high_l.0);
        let words = (self.total_pages + BITS - 1) / BITS;
        self.bitmap.resize(words, 0);
    }

    /// Map a PPN to its bitmap index (panic if out of range).
    fn bitmap_idx(&self, ppn: usize) -> usize {
        if ppn >= self.low_start && ppn < self.low_end {
            ppn - self.low_start
        } else if ppn >= self.high_start && ppn < self.high_end {
            (ppn - self.high_start) + (self.low_end - self.low_start)
        } else {
            panic!("Frame ppn={:#x} is not in any allocatable region", ppn);
        }
    }

    fn is_live_ppn(&self, ppn: usize) -> bool {
        (ppn >= self.low_start && ppn < self.low_current)
            || (ppn >= self.high_start && ppn < self.high_current)
    }
}

