/// thread create syscall
pub fn sys_thread_create(entry: usize, arg: usize) -> isize {
    trace!("sys_thread_create: Process {} create thread with entry {:#x} and arg {:#x}", current_process().getpid(), entry, arg);
    let task = current_task().unwrap();
    let process = task.process.upgrade().unwrap();
    // create a new thread
    let new_task = Arc::new(TaskControlBlock::new(
        Arc::clone(&process),
        task.inner_exclusive_access()
            .res
            .as_ref()
            .unwrap()
            .ustack_base,
        true,
        true,
    ));
    // add new task to scheduler
    add_task(Arc::clone(&new_task));
    let new_task_inner = new_task.inner_exclusive_access();
    let new_task_res = new_task_inner.res.as_ref().unwrap();
    let new_task_tid = new_task_res.tid;
    let new_task_global_tid = new_task.tid;
    let mut process_inner = process.inner_exclusive_access();
    // add new thread to current process
    let tasks = &mut process_inner.tasks;
    while tasks.len() < new_task_tid + 1 {
        tasks.push(None);
    }
    tasks[new_task_tid] = Some(Arc::clone(&new_task));
    let new_task_trap_cx = new_task_inner.get_trap_cx();
    #[cfg(target_arch = "riscv64")]
    {
        *new_task_trap_cx = TrapContext::app_init_context(
            entry,
            new_task_res.ustack_top(),
            kernel_token(),
            new_task.kstack.get_top(),
            trap_handler as usize,
        );
        (*new_task_trap_cx).x[10] = arg;
    }
    #[cfg(target_arch = "loongarch64")]
    {
        *new_task_trap_cx = TrapContext::app_init_context(
            entry,
            new_task_res.ustack_top(),
            0,
            new_task.kstack.get_top(),
            trap_handler as usize,
        );
        (*new_task_trap_cx).x[4] = arg;
    }
    new_task_global_tid as isize
}
/// get current thread id syscall
pub fn sys_gettid() -> isize {
    let task = current_task().unwrap();
    let tid = task.tid as isize;
    trace!("sys_gettid: Process {} thread tid={}", current_process().getpid(), tid);
    tid
}

/// wait for a thread to exit syscall
///
/// thread does not exist, return -1
/// thread has not exited yet, return -2
/// otherwise, return thread's exit code
pub fn sys_waittid(tid: usize) -> i32 {
    trace!("sys_waittid: Process {} wait for thread with tid {}", current_process().getpid(), tid);
    let task = current_task().unwrap();
    let process = task.process.upgrade().unwrap();
    let task_inner = task.inner_exclusive_access();
    let mut process_inner = process.inner_exclusive_access();
    // a thread cannot wait for itself
    if task_inner.res.as_ref().unwrap().tid == tid {
        return -1;
    }
    let mut exit_code: Option<i32> = None;
    let waited_task = process_inner.tasks[tid].as_ref();
    if let Some(waited_task) = waited_task {
        if let Some(waited_exit_code) = waited_task.inner_exclusive_access().exit_code {
            exit_code = Some(waited_exit_code);
        }
    } else {
        // waited thread does not exist
        return -1;
    }
    if let Some(exit_code) = exit_code {
        // dealloc the exited thread
        process_inner.tasks[tid] = None;
        exit_code
    } else {
        // waited thread has not exited
        -2
    }
}

/// set tid address
/// as the thread exit, it should wake up the address set
pub fn sys_set_tid_address(tidptr: *mut i32) -> isize {
    trace!("sys_set_tid_address: Process {} set tid address to {:?}", current_process().getpid(), tidptr);
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    inner.tid_clear_address = Some(tidptr as usize);
    task.tid as isize
}

