/// Set action for specified signal
pub fn sys_sigaction(signum: usize, act: *const SigAction, oldact: *mut SigAction, sigsetsize: usize) -> isize {
    trace!("sys_sigaction: Process {} set signal action for signal {} act {} oldact {} sigsetsize {}", current_process().getpid(), signum, act as usize, oldact as usize, sigsetsize);
    let token = current_user_token();
    let process = current_process();
    let mut inner = process.inner_exclusive_access();
    if sigsetsize != core::mem::size_of::<u64>() {
        return -EINVAL;
    }
    if signum == 0 || signum > 64 { return -EPERM; }
    if !oldact.is_null() {
        if inner.memory_set.translated_byte_buffer(oldact as *const u8, 1, 1).is_empty() {
            return -EFAULT;
        }
        *translated_refmut(token, oldact) = inner.signals_action[signum - 1];
    }
    if !act.is_null() {
        if inner.memory_set.translated_byte_buffer(act as *const u8, 1, 0).is_empty() {
            return -EFAULT;
        }
        let newact = *translated_ref(token, act);
        // SIGKILL and SIGSTOP cannot be caught
        if (signum == 9 || signum == 19) && newact.handler != 0 {
            return -EINVAL;
        }
        inner.signals_action[signum - 1] = newact;
    }
    0
}

/// Set proc signals mask
pub fn sys_sigprocmask(how: i32, set: *const u64, oldset: *mut u64, sigsetsize: usize) -> isize {
    trace!("sys_sigprocmask: Process {} set signal mask with how {} set {:#x} oldset {:#x} sigsetsize {}", current_process().getpid(), how, set as usize, oldset as usize, sigsetsize);
    let task = current_task().unwrap();
    let token = current_user_token();
    let mut inner = task.inner_exclusive_access();
    if sigsetsize != core::mem::size_of::<u64>() {
        return -EINVAL;
    }
    if !oldset.is_null() {
        if current_process().inner_exclusive_access().memory_set.translated_byte_buffer(oldset as *const u8, sigsetsize, 1).is_empty() {
            return -EFAULT;
        }
        *translated_refmut(token, oldset) = inner.signals_mask.bits();
    }
    if !set.is_null() {
        if current_process().inner_exclusive_access().memory_set.translated_byte_buffer(set as *const u8, sigsetsize, 0).is_empty() {
            return -EFAULT;
        }
        let new_mask: SignalFlags = SignalFlags::from_bits_truncate(*translated_ref(token, set as *const u64));
        // 不在入口过滤，与 Linux 一致：内核在递送时通过 force_sig 无视 mask
        match how {
            0 => inner.signals_mask |= new_mask,
            1 => inner.signals_mask &= !new_mask,
            2 => inner.signals_mask = new_mask,
            _ => return -EINVAL,
        }
    }
    0
}

/// stab
pub fn sys_sigtimedwait() -> isize {
    trace!("sys_sigtimedwait: Process {} wait for signal with timeout (not implemented, return -1)", current_process().getpid());
    0
}

